 </tr>
 </thead>
 <tbody className="divide-y divide-gray-100">
 {pendenciasExibidas.map((p: any) => (
 <tr key={p.IDRNC} onClick={() => loadPendenciaForEditOS(p)} className="hover:bg-amber-50/50 cursor-pointer transition-colors">
