 }`}
 >
 <h3 className="text-2xl font-bold mb-4">Features</h3>
 <ul className={`space-y-2 ${isDark ? 'text-gray-300' : 'text-gray-600'}`}>
 <li>ÔÇó Cinematic spring-based animations</li>
