 const pct = sumTotal > 0 ? Math.round((tot[1] / sumTotal) * 100) : 0;
 const IconComp = s.icon;
 return (
 <div key={s.key} className="flex flex-col gap-1.5 p-3 rounded-md border" style={{ backgroundColor: s.bg, borderColor: s.border }}>
