source:
import React, { useEffect, useState } from 'react';
import { Trash2, AlertTriangle, Loader2, Search, X, Box, FileText, Layers, FileCode, RefreshCw } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import { useToast } from '../contexts/ToastContext';

const API_BASE = '/api';

interface ParcialItem {
 IdOrdemServicoItemControle: number;
 IdOrdemServicoItem: number;
 IdOrdemServico: number;
 Processo: string;
 QtdeTotal: number;
 QtdeProduzida: number;
 CriadoPor: string;
 DataCriacao: string;
 CodMatFabricante: string;
 IdPlanodecorte?: number;
 EnderecoArquivo?: string;
 EnderecoArquivoItemOrdemServico?: string;
 Projeto: string;
 Tag: string;
}

export default function ApontamentosParciaisPage() {
 const { token, user } = useAuth();
 const { addToast } = useToast();
 
 const [parciais, setParciais] = useState<ParcialItem[]>([]);
 const [loading, setLoading] = useState(true);
 
 const [fOS, setFOS] = useState('');
 const [fProj, setFProj] = useState('');
 const [fTag, setFTag] = useState('');
 const [fPC, setFPC] = useState('');
 const [dataInicial, setDataInicial] = useState('');
 const [dataFinal, setDataFinal] = useState('');

 const [deletandoId, setDeletandoId] = useState<number | null>(null);

 const fetchParciais = async () => {
 setLoading(true);
 try {
 const res = await fetch(`${API_BASE}/apontamentos-parciais`, {
 headers: token ? { 'Authorization': `Bearer ${token}` } : undefined
 });
 const data = await res.json();
 if (data.success && data.parciais) {
 setParciais(data.parciais);
 }
 } catch (error) {
 console.error('Erro ao buscar parciais', error);
 } finally {
 setLoading(false);
 }
 };

 useEffect(() => {
 fetchParciais();
 }, [fetchParciais]);  

 const handleDelete = async (id: number) => {
 if (!window.confirm('Tem certeza que deseja estornar este apontamento parcial? A quantidade executada ser├í subtra├¡da do setor!')) return;
 
 setDeletandoId(id);
 try {
 const res = await fetch(`${API_BASE}/apontamentos-parciais/${id}`, {
 method: 'DELETE',
 headers: token ? { 'Authorization': `Bearer ${token}` } : undefined
 });
 const data = await res.json();
 if (data.success) {
 if (addToast) addToast({ type: 'success', title: 'Sucesso', message: 'Apontamento exclu├¡do com sucesso.' });
 else alert('Apontamento exclu├¡do com sucesso.');
 fetchParciais();
 } else {
 if (addToast) addToast({ type: 'error', title: 'Erro', message: data.message || 'Erro ao excluir apontamento.' });
 else alert(data.message || 'Erro ao excluir apontamento.');
 }
 } catch (err) {
 console.error(err);
 if (addToast) addToast({ type: 'error', title: 'Falha', message: 'Falha na comunica├º├úo com o servidor.' });
 else alert('Falha na comunica├º├úo com o servidor.');
 } finally {
 setDeletandoId(null);
 }
 };

 const formatDate = (dateString: string) => {
 if (!dateString) return '-';
 return dateString.replace('T', ' ').substring(0, 16);
 };

 const handleAbrirDesenho = async (it: ParcialItem, tipo: '3D' | 'PDF' | 'DXF' | 'PDF_ITEM') => {
 let path = '';
 switch (tipo) {
 case '3D': path = it.EnderecoArquivo || ''; break;
 case 'PDF': path = it.EnderecoArquivo || ''; break;
 case 'PDF_ITEM': path = it.EnderecoArquivoItemOrdemServico || ''; break;
 case 'DXF': path = it.EnderecoArquivo || ''; break;
 }

 if (!path) {
 if (addToast) addToast({ type: 'warning', title: 'Aviso', message: 'Caminho do arquivo n├úo localizado para este item.' });
 else alert('Caminho do arquivo n├úo localizado para este item.');
 return;
 }

 try {
 const headers: Record<string, string> = { 'Content-Type': 'application/json' };
 if (token) headers['Authorization'] = `Bearer ${token}`;

 const res = await fetch('/api/plano-corte/abrir-desenho', {
 method: 'POST',
 headers,
 body: JSON.stringify({ filePath: path, tipo, it })
 });
 const result = await res.json();
 if (!result.success) {
 if (addToast) addToast({ type: 'error', title: 'Erro ao Abrir', message: result.message });
 else alert(result.message);
 } else {
 if (addToast) addToast({ type: 'success', title: 'Sucesso', message: 'Desenho aberto.' });
 }
 } catch {
 if (addToast) addToast({ type: 'error', title: 'Erro', message: 'Falha na rede: ' + e.message });
 else alert('Falha na rede: ' + e.message);
 }
 };

 const limparFiltros = () => {
 setFOS('');
 setFProj('');
 setFTag('');
 setFPC('');
 setDataInicial('');
 setDataFinal('');
 };

 const filteredList = parciais.filter(p => {
 const matchOS = fOS ? String(p.IdOrdemServico).includes(fOS) : true;
 const matchProj = fProj ? (p.Projeto || '').toLowerCase().includes(fProj.toLowerCase()) : true;
 const matchTag = fTag ? (p.Tag || '').toLowerCase().includes(fTag.toLowerCase()) : true;
 const matchPC = fPC ? String(p.IdPlanodecorte || '').includes(fPC) : true;
 
 let matchDataIni = true;
 let matchDataFim = true;
 if (dataInicial || dataFinal) {
 let dataP = '';
 if (p.DataCriacao) {
 // p.DataCriacao vem em formato "DD/MM/YYYY HH:MM" do banco
 const dataPart = String(p.DataCriacao).substring(0, 10);
 if (dataPart.includes('/')) {
 const parts = dataPart.split('/');
 dataP = `${parts[2]}-${parts[1]}-${parts[0]}`; // Formata como YYYY-MM-DD
 } else {
 dataP = dataPart; // Se por acaso ja vier YYYY-MM-DD
 }
 }
 
 if (dataInicial && dataP) {
 matchDataIni = dataP >= dataInicial;
 }
 if (dataFinal && dataP) {
 matchDataFim = dataP <= dataFinal;
 }
 }

 return matchOS && matchProj && matchTag && matchPC && matchDataIni && matchDataFim;
 });

 return (
 <div className="flex flex-col h-[calc(100vh-80px)] overflow-hidden bg-gray-50 p-3 h-full flex flex-col min-h-0 gap-2">
 {/* Barra de filtros compacta */}
 <div className="flex flex-wrap items-center gap-2 shrink-0 bg-white px-3 py-2 rounded-lg shadow-sm border border-gray-200">
 {/* ├ìcone + t├¡tulo inline */}
 <div className="flex items-center gap-1.5 mr-2">
 <AlertTriangle size={14} className="text-amber-500 shrink-0" />
 <span className="text-xs font-bold text-gray-600 whitespace-nowrap">Apontamentos Parciais</span>
 </div>

 <div className="w-px h-5 bg-gray-200 shrink-0" />

 {/* Filtros de texto */}
 <div className="flex flex-wrap items-center gap-1 bg-gray-50 border border-gray-300 rounded-md px-2 py-1 focus-within:border-amber-400">
 <Search size={13} className="text-gray-400 shrink-0" />
 <div className="relative flex items-center">
 <input type="text" placeholder="O.S." value={fOS} onChange={e => setFOS(e.target.value)} className="pr-5 w-14 bg-transparent text-xs outline-none font-bold text-gray-700" />
 {fOS && <button onClick={() => setFOS('')} className="absolute right-0.5 text-slate-400 hover:text-red-500 bg-transparent border-none"><X size={11} /></button>}
 </div>
 <div className="relative flex items-center border-l border-gray-200 pl-1.5">
 <input type="text" placeholder="Projeto" value={fProj} onChange={e => setFProj(e.target.value)} className="pr-5 w-20 bg-transparent text-xs outline-none" />
 {fProj && <button onClick={() => setFProj('')} className="absolute right-0.5 text-slate-400 hover:text-red-500 bg-transparent border-none"><X size={11} /></button>}
 </div>
 <div className="relative flex items-center border-l border-gray-200 pl-1.5">
 <input type="text" placeholder="Tag" value={fTag} onChange={e => setFTag(e.target.value)} className="pr-5 w-16 bg-transparent text-xs outline-none" />
 {fTag && <button onClick={() => setFTag('')} className="absolute right-0.5 text-slate-400 hover:text-red-500 bg-transparent border-none"><X size={11} /></button>}
 </div>
 <div className="relative flex items-center border-l border-gray-200 pl-1.5">
 <input type="text" placeholder="Plano" value={fPC} onChange={e => setFPC(e.target.value)} className="pr-5 w-16 bg-transparent text-xs outline-none" />
 {fPC && <button onClick={() => setFPC('')} className="absolute right-0.5 text-slate-400 hover:text-red-500 bg-transparent border-none"><X size={11} /></button>}
 </div>
 </div>

 {/* Filtro de datas: Dt. Apontamento */}
 <div className="flex items-center gap-1.5 bg-gray-50 border border-gray-300 rounded-md px-2 py-1 focus-within:border-amber-400">
 <span className="text-[10px] font-bold text-gray-500 uppercase tracking-wide whitespace-nowrap">Dt. Apontamento</span>
 <input type="date" value={dataInicial} onChange={e => setDataInicial(e.target.value)} className="w-[105px] bg-transparent text-xs outline-none text-gray-500" />
 <span className="text-gray-400 text-xs">at├®</span>
 <input type="date" value={dataFinal} onChange={e => setDataFinal(e.target.value)} className="w-[105px] bg-transparent text-xs outline-none border-l border-gray-200 pl-1.5 text-gray-500" />
 {(fOS || fProj || fTag || fPC || dataInicial || dataFinal) && (
 <button onClick={limparFiltros} className="p-0.5 text-gray-400 hover:text-red-500 transition-colors border-l border-gray-200 pl-1.5" title="Limpar Filtros"><X size={13}/></button>
 )}
 </div>

 <button onClick={fetchParciais} className="ml-auto px-3 py-1.5 bg-amber-500 hover:bg-amber-600 text-white rounded-md font-bold shadow-sm transition-colors text-xs flex items-center gap-1.5">
 <RefreshCw size={12} /> Atualizar
 </button>
 </div>

 <div className="flex-1 overflow-hidden flex flex-col bg-white rounded-md shadow-sm border border-gray-200">
 <div className="overflow-x-auto flex-1">
 <table className="w-full text-left">
 <thead className="bg-[#567469] text-white bg-[#567469] text-white bg-[#567469] text-white text-xs uppercase tracking-wider sticky top-0 z-10">
 <tr>
 <th className="px-3 py-1.5 font-bold w-32 border-b border-[#4d665d]">Data / Hora</th>
 <th className="px-3 py-1.5 font-bold w-24 border-b border-[#4d665d] text-center">Plano de Corte</th>
 <th className="px-3 py-1.5 font-bold w-28 border-b border-[#4d665d]">Respons├ível</th>
 <th className="px-3 py-1.5 font-bold w-24 border-b border-[#4d665d] text-center">O.S.</th>
 <th className="px-3 py-1.5 font-bold w-32 border-b border-[#4d665d] text-center">Setor</th>
 <th className="px-3 py-1.5 font-bold border-b border-[#4d665d]">Pe├ºa / Projeto / Tag</th>
 <th className="px-3 py-1.5 font-bold w-24 text-center border-b border-[#4d665d]">Qtde Parcial</th>
 <th className="px-3 py-1.5 font-bold w-40 text-center border-b border-[#4d665d]">A├º├Áes</th>
 </tr>
 </thead>
 <tbody className="text-sm divide-y divide-gray-100">
 {loading && (
 <tr>
 <td colSpan={8} className="px-4 py-8 text-center text-gray-500">
 <div className="flex flex-col items-center gap-2">
 <Loader2 size={24} className="animate-spin text-amber-500" />
 Carregando hist├│rico...
 </div>
 </td>
 </tr>
 )}
 
 {!loading && filteredList.length === 0 && (
 <tr>
 <td colSpan={8} className="px-4 py-8 text-center text-gray-500 font-medium bg-gray-50">
 Nenhum apontamento parcial registrado que corresponda aos filtros.
 </td>
 </tr>
 )}

 {!loading && filteredList.map(item => (
 <tr key={item.IdOrdemServicoItemControle} className="hover:bg-amber-50/50 transition-colors">
 <td className="px-4 py-2 font-medium text-gray-600 text-xs">
 {formatDate(item.DataCriacao)}
 </td>
 <td className="px-4 py-2 text-center text-xs">
 {item.IdPlanodecorte ? (
 <span className="bg-sky-100 text-sky-700 font-black px-2 py-1 rounded shadow-sm text-xs border border-sky-200">
 Pl. {item.IdPlanodecorte}
 </span>
 ) : (
 <span className="text-gray-400 text-xs">ÔÇö</span>
 )}
 </td>
 <td className="px-4 py-2 text-gray-700 font-bold truncate max-w-[120px]" title={item.CriadoPor}>
 {item.CriadoPor}
 </td>
 <td className="px-4 py-2 text-center text-xs">
 <span className="bg-[#E0E800]/40 text-[#32423D] font-black px-2 py-0.5 rounded shadow-sm">
 OS {item.IdOrdemServico}
 </span>
 </td>
 <td className="px-4 py-2 text-center">
 <span className="uppercase text-[10px] font-black border border-gray-300 bg-gray-100 px-2 py-1 rounded">
 {item.Processo}
 </span>
 </td>
 <td className="px-4 py-2">
 <div className="flex flex-col gap-0.5">
 <span className="font-bold text-[#32423D] text-xs">{(item.CodMatFabricante || '').substring(0,25)}</span>
 <div className="flex gap-1 flex-wrap">
 {item.Projeto && <span className="text-[9px] bg-purple-100 text-purple-700 font-medium px-1 rounded truncate max-w-[100px]">{item.Projeto}</span>}
 {item.Tag && <span className="text-[9px] bg-green-100 text-green-700 font-medium px-1 rounded truncate max-w-[100px]">{item.Tag}</span>}
 </div>
 </div>
 </td>
 <td className="px-4 py-2 text-center">
 <span className="inline-block min-w-[60px] text-center font-black text-amber-700 bg-amber-100 border border-amber-200 px-2 py-1 rounded">
 {item.QtdeProduzida} / {item.QtdeTotal}
 </span>
 </td>
 <td className="px-4 py-2 text-center">
 <div className="flex items-center justify-center gap-1">
 <button onClick={() => handleAbrirDesenho(item, '3D')} className="p-1 hover:bg-[#E0E800]/20 text-[#32423D] rounded transition-colors" title="Abrir 3D (SolidWorks)"><Box size={14}/></button>
 <button onClick={() => handleAbrirDesenho(item, 'PDF')} className="p-1 hover:bg-red-100 text-red-600 rounded transition-colors" title="Abrir Desenho PDF"><FileText size={14}/></button>
 <button onClick={() => handleAbrirDesenho(item, 'DXF')} className="p-1 hover:bg-emerald-100 text-emerald-600 rounded transition-colors" title="Abrir Desenho DXF"><Layers size={14}/></button>
 <button onClick={() => handleAbrirDesenho(item, 'PDF_ITEM')} className="p-1 hover:bg-amber-100 text-amber-600 rounded transition-colors" title="Abrir PDF do Item"><FileCode size={14}/></button>
 
 <div className="w-px h-5 bg-gray-200 mx-1"></div>
 
 {(user?.role === 'admin' || user?.isSuperadmin) ? (
 <button 
 onClick={() => handleDelete(item.IdOrdemServicoItemControle)}
 disabled={deletandoId === item.IdOrdemServicoItemControle}
 className="p-1.5 text-red-500 hover:bg-red-50 text-[10px] uppercase font-bold hover:text-red-700 rounded transition-colors border border-transparent hover:border-red-200"
 title="Estornar Apontamento"
 >
 {deletandoId === item.IdOrdemServicoItemControle ? (
 <Loader2 size={14} className="animate-spin" />
 ) : (
 <Trash2 size={14} />
 )}
 </button>
 ) : (
 <span className="text-gray-300 text-[10px] uppercase block px-1">ÔÇö</span>
 )}
 </div>
 </td>
 </tr>
 ))}
 </tbody>
 </table>
 </div>
 </div>
 </div>
 );
}

import React, { useEffect, useState } from 'react';
import { useParams, useSearchParams } from 'react-router-dom';
import { useAlert } from '../../contexts/AlertContext';

interface PlanilhaInfo {
 IdPlanilha: number;
 NomeArquivo: string;
 NomeProjeto: string;
 NomeTag: string;
 DataImportacao: string;
 Revisao: number;
}

interface BlockSetData {
 IdDadosBlockSet: number;
 Cubicle: string;
 Cubicle_type: string;
 FU: string;
 Info: string;
 Part_reference: string;
 Part_description: string;
 Part_total_qty: number;
 Mass_per_part_kg: number;
}

const BlockSet: React.FC = () => {
 const [searchParams] = useSearchParams();
 const idPlanilha = searchParams.get('id');
 const { showAlert } = useAlert();
 const [planilha, setPlanilha] = useState<PlanilhaInfo | null>(null);
 const [dados, setDados] = useState<BlockSetData[]>([]);
 const [loading, setLoading] = useState<boolean>(true);

 useEffect(() => {
 if (!idPlanilha) {
 showAlert('error', 'Erro', 'ID da Planilha n├úo fornecido.');
 setLoading(false);
 return;
 }

 const fetchData = async () => {
 try {
 const response = await fetch(`/api/blockset/data/${idPlanilha}`);
 const data = await response.json();
 if (data.success) {
 setPlanilha(data.planilha);
 setDados(data.dados);
 } else {
 showAlert('error', 'Erro', data.message || 'Erro ao carregar dados.');
 }
 } catch (error) {
 console.error('Erro na requisi├º├úo:', error);
 showAlert('error', 'Erro', 'Erro de conex├úo ao carregar dados.');
 } finally {
 setLoading(false);
 }
 };

 fetchData();
 }, [idPlanilha]);

 if (loading) {
 return (
 <div className="flex items-center justify-center min-h-screen bg-[#0B1120]">
 <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-[#32423D]"></div>
 </div>
 );
 }

 if (!planilha) {
 return (
 <div className="flex flex-col items-center justify-center min-h-screen bg-[#0B1120] text-white p-6">
 <h1 className="text-3xl font-bold mb-4">Nenhum Dado Encontrado</h1>
 <p className="text-gray-400">A planilha solicitada n├úo existe ou n├úo p├┤de ser carregada.</p>
 </div>
 );
 }

 return (
 <div className="min-h-screen bg-[#0B1120] text-gray-200 p-8 font-sans">
 <div className="max-w-7xl mx-auto space-y-6">
 {/* Header Card */}
 <div className="bg-[#111827] rounded-md border border-gray-800 p-6 shadow-2xl relative overflow-hidden">
 <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-500 to-cyan-400"></div>
 <h1 className="text-3xl font-bold text-white mb-2 flex items-center gap-3">
 <span className="bg-[#E0E800]/200/10 text-blue-400 p-2 rounded-lg">
 <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path>
 </svg>
 </span>
 Visualiza├º├úo de Planilha BlockSet
 </h1>

 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mt-6">
 <div className="bg-[#1F2937] p-4 rounded-lg border border-gray-700">
 <p className="text-sm text-gray-400 mb-1">Projeto / Tag</p>
 <p className="font-medium text-white">{planilha.NomeProjeto} / {planilha.NomeTag}</p>
 </div>
 <div className="bg-[#1F2937] p-4 rounded-lg border border-gray-700">
 <p className="text-sm text-gray-400 mb-1">Arquivo Original</p>
 <p className="font-medium text-white truncate" title={planilha.NomeArquivo}>{planilha.NomeArquivo}</p>
 </div>
 <div className="bg-[#1F2937] p-4 rounded-lg border border-gray-700">
 <p className="text-sm text-gray-400 mb-1">Data de Importa├º├úo</p>
 <p className="font-medium text-white">{new Date(planilha.DataImportacao).toLocaleString('pt-BR')}</p>
 </div>
 <div className="bg-[#1F2937] p-4 rounded-lg border border-gray-700">
 <p className="text-sm text-gray-400 mb-1">Revis├úo</p>
 <p className="font-medium text-blue-400">Rev {planilha.Revisao}</p>
 </div>
 </div>
 </div>

 {/* Table Data */}
 <div className="bg-[#111827] rounded-md border border-gray-800 shadow-xl overflow-hidden">
 <div className="overflow-x-auto">
 <table className="w-full text-left border-collapse">
 <thead>
 <tr className="bg-[#1F2937] border-b border-gray-700">
 <th className="py-4 px-6 text-xs uppercase tracking-wider font-semibold text-gray-300">Cubicle</th>
 <th className="py-4 px-6 text-xs uppercase tracking-wider font-semibold text-gray-300">Type</th>
 <th className="py-4 px-6 text-xs uppercase tracking-wider font-semibold text-gray-300">FU</th>
 <th className="py-4 px-6 text-xs uppercase tracking-wider font-semibold text-gray-300">Refer├¬ncia</th>
 <th className="py-4 px-6 text-xs uppercase tracking-wider font-semibold text-gray-300">Descri├º├úo</th>
 <th className="py-4 px-6 text-xs uppercase tracking-wider font-semibold text-gray-300">Qtd</th>
 <th className="py-4 px-6 text-xs uppercase tracking-wider font-semibold text-gray-300">Massa (kg)</th>
 </tr>
