import React, { useEffect, useState } from 'react';
import { 
 FileSpreadsheet, Loader2, ArrowLeft, Download
} from 'lucide-react';
import { useAlert } from '../../contexts/AlertContext';
import * as XLSX from 'xlsx';

interface ProcessableItem {
 Part_Reference: string;
 Revisao: number;
 Part_total_qty: number;
 DescricaoOS: string;
}

interface PivotRow {
 Part_Reference: string;
 revisions: {
 [rev: number]: {
 qty: number;
 osDesc: string;
 }
 };
 deltaTotal: number;
}

interface PowerBuildAgglutinationProps {
 onNavigate?: (pageId: string) => void;
}

const PowerBuildAgglutination: React.FC<PowerBuildAgglutinationProps> = ({ onNavigate }) => {
 const { showAlert } = useAlert();

 // Data states
 const [pivotData, setPivotData] = useState<PivotRow[]>([]);
 const [maxRev, setMaxRev] = useState<number>(0);
 const [loading, setLoading] = useState(true);

 const [contextInfo, setContextInfo] = useState({
 projeto: '',
 tag: '',
 planilha: ''
 });

 useEffect(() => {
 const fetchPivotData = async () => {
 setLoading(true);
 try {
 const idProjeto = localStorage.getItem('agglutination_filter_projeto') || '';
 const idTag = localStorage.getItem('agglutination_filter_tag') || '';
 const nomePlanilha = localStorage.getItem('agglutination_filter_planilha') || '';

 if (!idProjeto || !idTag || !nomePlanilha) {
 setLoading(false);
 showAlert('Filtros n├úo encontrados. Volte ├á Lista de Itens e selecione Projeto, Tag e Planilha primeiro.', 'warning');
 return;
 }

 setContextInfo({ projeto: idProjeto, tag: idTag, planilha: nomePlanilha });

 const res = await fetch('/api/blockset/processable-items', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({
 idProjeto,
 idTag,
 nomePlanilha,
 revisao: -1 // GET ALL REVISIONS!
 })
 });

 const data = await res.json();
 if (data.success) {
 const rawItems: ProcessableItem[] = data.data;

 // Transform into Pivot Table
 const pivotMap: { [codMat: string]: PivotRow } = {};
 let highestRev = 0;

 rawItems.forEach(item => {
 if (item.Revisao > highestRev) highestRev = item.Revisao;

 if (!pivotMap[item.Part_Reference]) {
 pivotMap[item.Part_Reference] = {
 Part_Reference: item.Part_Reference,
 revisions: {},
 deltaTotal: 0
 };
 }

 pivotMap[item.Part_Reference].revisions[item.Revisao] = {
 qty: item.Part_total_qty,
 osDesc: item.DescricaoOS || ''
 };
 });

 // Calculate Delta based on user rule:
 // se a quantidade da ultima revisao for maior que a maior quantidade das revisoes anteriores:
 // delta = ultima_revisao - maior_das_anteriores
 // caso contrario: 0
 const pivotArray = Object.values(pivotMap).sort((a, b) => a.Part_Reference.localeCompare(b.Part_Reference));

 pivotArray.forEach(row => {
 const revs = Object.keys(row.revisions).map(Number).sort((a, b) => a - b);
 if (revs.length === 0) return;

 const lastRev = revs[revs.length - 1];
 const lastRevQty = row.revisions[lastRev].qty;

 let maxPrevQty = 0;
 for (let i = 0; i < revs.length - 1; i++) {
 const qty = row.revisions[revs[i]].qty;
 if (qty > maxPrevQty) {
 maxPrevQty = qty;
 }
 }

 if (lastRevQty > maxPrevQty) {
 row.deltaTotal = lastRevQty - maxPrevQty;
 } else {
 row.deltaTotal = 0;
 }
 });

 setPivotData(pivotArray);
 setMaxRev(highestRev);
 } else {
 showAlert('Erro ao buscar dados: ' + data.message, 'error');
 }
 } catch (error) {
 showAlert('Erro de conex├úo ao buscar dados', 'error');
 } finally {
 setLoading(false);
 }
 };

 fetchPivotData();
 }, [showAlert]);

 const handleExportExcel = () => {
 if (pivotData.length === 0) {
 showAlert('N├úo h├í dados para exportar.', 'warning');
 return;
 }

 const dataToExport = pivotData.map(row => {
 const obj: any = {
 'Refer├¬ncia P': row.Part_Reference,
 };

 for (let i = 0; i <= maxRev; i++) {
 const revData = row.revisions[i] || { qty: '', osDesc: '' };
 obj[`Rev ${i} / Qtde`] = revData.qty;
 obj[`OS Rev ${i}`] = revData.osDesc;
 }

 obj['╬ö Total Inserido'] = row.deltaTotal;
 return obj;
 });

 const ws = XLSX.utils.json_to_sheet(dataToExport);
 const wb = XLSX.utils.book_new();
 XLSX.utils.book_append_sheet(wb, ws, "Resumo Fabricacao");
 XLSX.writeFile(wb, `Resumo_Fabricacao_${contextInfo.planilha.replace('.xlsx', '')}.xlsx`);
 };

 return (
 <div className="flex flex-col h-[calc(100vh-80px)] overflow-hidden bg-gray-50 p-6 font-sans">

 {/* Header */}
 <div className="flex items-center justify-between mb-6 shrink-0">
 <div className="flex items-center gap-4">
 {onNavigate && (
 <button 
 onClick={() => onNavigate('powerbuild-list')}
 className="p-2 hover:bg-gray-200 rounded-full transition-colors bg-white border border-gray-200 shadow-sm"
 title="Voltar para Lista"
 >
 <ArrowLeft className="w-5 h-5 text-gray-600" />
 </button>
 )}
 <div className="bg-white p-3 rounded-md shadow-sm border border-gray-200">
 <FileSpreadsheet className="w-6 h-6 text-indigo-600" />
 </div>
 <div>
 <h1 className="text-2xl font-black text-gray-800 tracking-tight">Resumo de Fabrica├º├úo por Refer├¬ncia P</h1>
 <p className="text-sm text-gray-500 font-medium mt-0.5">
 Planilha: <strong className="text-gray-700">{contextInfo.planilha || 'Nenhuma selecionada'}</strong>
 </p>
 </div>
 </div>

 <button 
 onClick={handleExportExcel}
 disabled={pivotData.length === 0}
 className={`px-4 py-2 rounded-lg text-sm font-bold border transition-all flex items-center gap-2 shadow-sm ${
 pivotData.length > 0 
 ? 'bg-green-600 hover:bg-green-700 text-white border-green-700' 
 : 'bg-gray-100 text-gray-400 border-gray-200 cursor-not-allowed'
 }`}
 >
 <Download className="w-4 h-4" />
 Exportar Excel
 </button>
 </div>

 <div className="flex-1 overflow-auto custom-scrollbar bg-white rounded-md border border-gray-200 shadow-sm">
 {loading ? (
 <div className="flex flex-col items-center justify-center h-full space-y-4">
 <Loader2 className="w-10 h-10 animate-spin text-indigo-600" />
 <p className="text-gray-500 font-medium">Carregando matriz de revis├Áes...</p>
 </div>
 ) : pivotData.length === 0 ? (
 <div className="flex flex-col items-center justify-center h-full space-y-4">
 <FileSpreadsheet className="w-16 h-16 text-gray-200" />
 <p className="text-gray-500 font-medium">Nenhum dado encontrado ou planilha n├úo selecionada na tela anterior.</p>
 <button 
 onClick={() => onNavigate && onNavigate('powerbuild-list')}
 className="text-indigo-600 font-bold hover:underline"
 >
 Voltar e selecionar uma planilha
 </button>
 </div>
 ) : (
 <table className="w-full text-left border-collapse whitespace-nowrap min-w-max">
 <thead className="sticky top-0 z-10 bg-gray-50 border-b border-gray-200 shadow-sm">
 <tr>
 <th className="py-4 px-6 text-xs font-bold text-gray-700 uppercase tracking-wider border-r border-gray-200 bg-gray-100">
 Refer├¬ncia P
 </th>
 {Array.from({ length: maxRev + 1 }).map((_, i) => (
 <React.Fragment key={i}>
 <th className="py-4 px-4 text-xs font-bold text-gray-600 uppercase tracking-wider text-center border-r border-gray-200">
 Rev {i} / Qtde
 </th>
 <th className="py-4 px-6 text-xs font-bold text-gray-600 uppercase tracking-wider border-r border-gray-200 bg-white">
 OS Rev {i}
 </th>
 </React.Fragment>
 ))}
 <th className="py-4 px-6 text-xs font-bold text-indigo-700 uppercase tracking-wider bg-indigo-50">
 ╬ö Total Inserido
 </th>
 </tr>
 </thead>
 <tbody className="divide-y divide-gray-100">
 {pivotData.map((row, idx) => (
 <tr key={idx} className="hover:bg-indigo-50/30 transition-colors">
 <td className="py-3 px-6 border-r border-gray-100 bg-gray-50/50">
 <span className="font-bold text-gray-800 text-sm">{row.Part_Reference}</span>
 </td>

 {Array.from({ length: maxRev + 1 }).map((_, i) => {
 const rev = row.revisions[i];
 return (
 <React.Fragment key={i}>
 <td className="py-3 px-4 text-center border-r border-gray-100">
 <span className="font-medium text-gray-700">{rev?.qty ?? ''}</span>
 </td>
 <td className="py-3 px-6 border-r border-gray-100 text-xs text-gray-600">
 {rev?.osDesc ?? ''}
 </td>
 </React.Fragment>
 );
 })}

 <td className="py-3 px-6 bg-indigo-50/30">
 <span className={`font-bold text-sm ${row.deltaTotal > 0 ? 'text-indigo-600' : 'text-gray-400'}`}>
 {row.deltaTotal}
 </span>
 </td>
 </tr>
 ))}
 </tbody>
 </table>
 )}
 </div>

 {/* Footer Info */}
 {pivotData.length > 0 && (
 <div className="flex items-center justify-between text-sm text-gray-500 px-2 mt-4 shrink-0">
 <span>Total de Refer├¬ncias: <strong className="text-gray-800">{pivotData.length}</strong></span>
 <span>Revis├úo M├íxima Encontrada: <strong className="text-gray-800">Rev {maxRev}</strong></span>
 </div>
 )}
 </div>
 );
};

export default PowerBuildAgglutination;

import React, { useState, useEffect } from 'react';
import { 
 FilePlus, Upload, ShieldAlert, Clock, 
 Database, Tag as TagIcon, CheckCircle2, 
 AlertTriangle, Loader2, FileSpreadsheet,
 Layers, Trash2, Settings2
} from 'lucide-react';
import { useAlert } from '../../contexts/AlertContext';
import { useAuth } from '../../contexts/AuthContext';

interface Projeto {
 IdProjeto: number;
 Projeto: string;
}

interface Tag {
 IdTag: number;
 Tag: string;
}

interface PlanilhaMaster {
 NomeArquivo: string;
}

const PowerBuildImport: React.FC = () => {
 const { showAlert } = useAlert();
 const { user } = useAuth();
 const [loading, setLoading] = useState(false);
 const [initializing, setInitializing] = useState(false);

 // Form States
 const [projetos, setProjetos] = useState<Projeto[]>([]);
 const [tags, setTags] = useState<Tag[]>([]);
 const [selectedProjeto, setSelectedProjeto] = useState<string>('');
 const [selectedTag, setSelectedTag] = useState<string>('');
 const [file, setFile] = useState<File | null>(null);
 const [isRevision, setIsRevision] = useState(false);
 const [masterPlanilhas, setMasterPlanilhas] = useState<PlanilhaMaster[]>([]);
 const [selectedMaster, setSelectedMaster] = useState('');
 const [showTruncate, setShowTruncate] = useState(false);

 useEffect(() => {
 fetchProjetos();
 // Check structure on mount
 handleInitDB();
 }, []);

 useEffect(() => {
 if (selectedProjeto) {
 fetchTags(parseInt(selectedProjeto));
 fetchMasterPlanilhas(parseInt(selectedProjeto));
 } else {
 setTags([]);
 setMasterPlanilhas([]);
 }
 }, [selectedProjeto]);

 const fetchProjetos = async () => {
 try {
 // Aplicar filtros: Liberado='S' e N├úo Finalizado
 const res = await fetch('/api/projeto?liberado=S&finalizado=N');
 const data = await res.json();
 if (data.success) setProjetos(data.data);
 } catch (e) {
 console.error('Erro ao buscar projetos:', e);
 showAlert('Erro ao carregar lista de projetos.', 'error');
 }
 };

 const fetchTags = async (idProj: number) => {
 try {
 const res = await fetch(`/api/projeto/${idProj}/tags`);
 const data = await res.json();
 if (data.success) setTags(data.data);
 } catch (e) {
 console.error('Erro ao buscar tags:', e);
 showAlert('Erro ao carregar lista de tags.', 'error');
 }
 };

 const fetchMasterPlanilhas = async (idProj: number) => {
 try {
 const res = await fetch('/api/blockset/files');
 if (!res.ok) throw new Error(`HTTP ${res.status}`);

 const data = await res.json();
 if (data.success) {
 // Filter planilhas for this project
 const filtered = data.data
 .filter((p: any) => p.IdProjeto === idProj)
 .map((p: any) => ({ NomeArquivo: p.NomeArquivo }));

 // Unique file names
 const unique = Array.from(new Set(filtered.map((p: any) => p.NomeArquivo)))
 .map(name => ({ NomeArquivo: name as string }));

 setMasterPlanilhas(unique);
 }
 } catch (e) {
 console.error('Erro ao buscar planilhas mestre:', e);
 showAlert('Erro ao carregar hist├│rico de planilhas.', 'error');
 }
 };

 const handleInitDB = async () => {
 setInitializing(true);
 try {
 const res = await fetch('/api/blockset/init-db', { method: 'POST' });

 if (res.status === 401) {
 showAlert('Sess├úo expirada. Por favor, fa├ºa login novamente.', 'error');
 return;
 }

 if (!res.ok) {
 const text = await res.text();
 console.error('Init DB Error:', text);
 showAlert(`Erro no servidor (${res.status}).`, 'error');
 return;
 }

 const data = await res.json();
 if (!data.success) {
 showAlert(data.message || 'Falha ao inicializar estrutura.', 'error');
 }
 } catch (e) {
 console.error('Connection Error:', e);
 showAlert('Erro de conex├úo ao servidor.', 'error');
 } finally {
 setInitializing(false);
 }
 };

 const handleTruncate = async () => {
 if (!window.confirm('ATEN├ç├âO: Isso apagar├í TODOS os dados de importa├º├úo de planilhas. Deseja continuar?')) return;

 setLoading(true);
 try {
 const res = await fetch('/api/blockset/truncate', { method: 'POST' });
 const data = await res.json();
 if (data.success) {
 showAlert('Tabelas limpas com sucesso!', 'success');
 } else {
 showAlert(data.message, 'error');
 }
 } catch (e) {
 showAlert('Erro de conex├úo.', 'error');
 } finally {
 setLoading(false);
 }
 };

 const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
 if (e.target.files && e.target.files[0]) {
 setFile(e.target.files[0]);
 }
 };

 const handleSubmit = async (e: React.FormEvent) => {
 e.preventDefault();
 if (!selectedProjeto || !selectedTag || !file) {
 showAlert('Preencha todos os campos e selecione um arquivo.', 'warning');
 return;
 }

 if (isRevision && !selectedMaster) {
 showAlert('Selecione a planilha mestre para vincular a revis├úo.', 'warning');
 return;
 }

 setLoading(true);
 const formData = new FormData();
 formData.append('file', file);
 formData.append('idProjeto', selectedProjeto);
 formData.append('idTag', selectedTag);

 const projName = (Array.isArray(projetos) ? projetos : []).find(p => p.IdProjeto?.toString() === selectedProjeto)?.Projeto || '';
 const tagName = (Array.isArray(tags) ? tags : []).find(t => t.IdTag?.toString() === selectedTag)?.Tag || '';

 formData.append('nomeProjeto', projName);
 formData.append('nomeTag', tagName);
 formData.append('isRevision', isRevision.toString());
 formData.append('masterFileName', selectedMaster);

 try {
 const res = await fetch('/api/blockset/import', {
 method: 'POST',
 body: formData
 });
 const data = await res.json();
 if (data.success) {
 showAlert(data.message, 'success');
 // Reset file
 setFile(null);
 } else {
 showAlert(data.message, 'error');
 }
 } catch (error) {
 showAlert('Erro ao realizar importa├º├úo.', 'error');
 } finally {
 setLoading(false);
 }
 };

 return (
 <div className="flex flex-col h-[calc(100vh-80px)] overflow-hidden bg-gray-50 p-6 font-sans">

 {/* Header Section */}
 <div className="flex flex-wrap items-center justify-between gap-4 mb-6 shrink-0 bg-white p-4 rounded-md shadow-sm border border-gray-200">
 <div className="flex items-center gap-3">
 <div className="w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center text-[#32423D]">
 <FilePlus size={24} />
 </div>
 <div>
 <h1 className="text-2xl font-black text-[#567469] tracking-tight">Leitura de Dados (Power Build)</h1>
 <p className="text-sm text-gray-500 font-medium">Importe planilhas BlockSet (data) ou PixEasy (bom) para o sistema.</p>
 </div>
 </div>

 <div className="flex flex-wrap gap-2 items-center">
 {user?.dbName === 'lynxlocal' && (
 <button 
 onClick={handleTruncate}
 className="flex items-center gap-2 px-4 py-2 bg-red-50 text-red-600 border border-red-200 rounded-lg hover:bg-red-100 transition-all text-sm font-bold shadow-sm"
 >
 <Trash2 className="w-4 h-4" />
 Limpar Base (Truncate)
 </button>
 )}
 </div>
 </div>

 <div className="flex-1 overflow-auto custom-scrollbar">
 <div className="max-w-4xl mx-auto space-y-6 pb-8">
 {initializing && (
 <div className="bg-[#E0E800]/20 border border-blue-200 p-4 rounded-md flex items-center gap-3 text-[#32423D]">
 <Loader2 className="w-5 h-5 animate-spin" />
 <span className="text-sm font-medium">Verificando estrutura do banco de dados...</span>
 </div>
 )}

 <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
 {/* Main Form Card */}
 <div className="lg:col-span-2 space-y-6">
 <form onSubmit={handleSubmit} className="bg-white rounded-md border border-gray-200 p-8 shadow-sm space-y-6 relative overflow-hidden">

 {/* Step 1: Context Selection */}
 <div className="space-y-4">
 <div className="flex items-center gap-2 text-blue-400 font-bold text-xs uppercase tracking-widest">
 <Layers className="w-4 h-4" />
 1. Definir Contexto
 </div>
