 onClick={() => setIsRevision(false)}
 className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${!isRevision ? 'bg-white text-[#32423D] shadow-sm border border-gray-200' : 'text-gray-500 hover:text-gray-700'}`}
