 if (!selectedOS) {
 showAlert('Selecione a Ordem de Servi├ºo de destino antes de pesquisar os itens.', 'warning');
 return;
 }

 setLoading(true);
 try {
 const res = await fetch('/api/blockset/processable-items', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({
 idProjeto: selectedProjeto,
 idTag: selectedTag,
 nomePlanilha: selectedPlanilha,
 revisao: selectedRevisao === 'Todas' ? -1 : selectedRevisao,
 codMatFilter: codMatFilter
 })
 });
 const data = await res.json();
 if (data.success) {
 setItems(data.data.map((item: any) => ({ ...item, selected: false })));
 if (data.data.length === 0) {
 showAlert('Nenhum item encontrado para os filtros selecionados.', 'info');
 }
 } else {
 showAlert(data.message, 'error');
 }
 } catch (error) {
 showAlert('Erro ao buscar itens.', 'error');
 } finally {
 setLoading(false);
 }
 };

 const handleToggleSelectAll = (select: boolean) => {
 setItems(prev => prev.map(item => ({ ...item, selected: select })));
 };

 const handleToggleItem = (id: number) => {
 setItems(prev => prev.map(item => item.IdDado === id ? { ...item, selected: !item.selected } : item));
 };

 const handleSave = async () => {
 const selectedItems = items.filter(i => i.selected);
 if (selectedItems.length === 0) {
 showAlert('Nenhum item selecionado.', 'warning');
 return;
 }
 if (!selectedOS) {
 showAlert('Selecione uma Ordem de Servi├ºo de destino.', 'warning');
 return;
 }

 // Confirmation (Aglutinado Mode)
 const confirmMsg = "Aten├º├úo: Todos os itens existentes nesta OS ser├úo EXCLU├ìDOS e substitu├¡dos pelos itens selecionados. Deseja continuar?";
 if (!window.confirm(confirmMsg)) return;

 setProcessing(true);
 try {
 const res = await fetch('/api/blockset/process-items', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({
 idOSDestino: selectedOS,
 items: selectedItems,
 usuario: user?.nome || 'Sistema'
 })
 });
 const data = await res.json();
 if (data.success) {
 showAlert(data.message, 'success');
 if (data.missingMaterials?.length > 0) {
 showAlert(`${data.missingMaterials.length} materiais n├úo cadastrados foram enviados para a lista de pendentes.`, 'warning');
 }
 // Refresh list
 handleSearch();
 } else {
 showAlert(data.message, 'error');
 }
 } catch (error) {
 showAlert('Erro no processamento.', 'error');
 } finally {
 setProcessing(false);
 }
 };

 const handleClear = () => {
 setSelectedProjeto('');
 setSelectedTag('');
 setSelectedPlanilha('');
 setSelectedRevisao(-1);
 setSelectedOS('');
 setCodMatFilter('');
