// ÔöÇÔöÇÔöÇ Reusable Field ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function EditableField({ icon, label, value, onChange, readOnly, type }: {
 icon: React.ReactNode; label: string; value: string;
 onChange?: (v: string) => void; readOnly?: boolean; type?: string;
}) {
 return (
 <div className="flex items-center gap-2 min-w-0">
