 value={formData.valor}
 onChange={(e) => setFormData({ ...formData, valor: e.target.value })}
 />
 </div>

 <div>
 <label className="block text-sm font-medium text-gray-700 mb-1">Descri├º├úo</label>
 <input
 type="text"
 className="w-full px-4 py-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-[#32423D] focus:border-transparent outline-none transition-all"
 placeholder="Descri├º├úo opcional"
 value={formData.descricao || ''}
 onChange={(e) => setFormData({ ...formData, descricao: e.target.value })}
 />
 </div>

 <div className="flex justify-end gap-3 pt-4 mt-2 border-t border-gray-50">
 <button
 type="button"
 onClick={() => setShowModal(false)}
 className="px-4 py-2 text-gray-500 hover:bg-gray-100 rounded-lg font-medium transition-colors"
 >
 Cancelar
 </button>
 <button
 type="submit"
 disabled={submitting}
 className="flex items-center gap-2 bg-[#32423D] text-[#E0E800] px-6 py-2 rounded-lg font-bold hover:bg-[#2a3833] transition-colors shadow-lg shadow-[#32423D]/20 disabled:opacity-70 disabled:cursor-not-allowed"
 >
 {submitting ? <Loader2 className="animate-spin" size={20} /> : <Check size={20} />}
 {editingConfig ? 'Salvar Altera├º├Áes' : 'Criar Configura├º├úo'}
 </button>
 </div>
 </form>
 </div>
 </div>
 )}
 </div>
 );
}

import React, { useState, useEffect } from 'react';
import { Plus, Edit2, Trash2, Save, X } from 'lucide-react';
import { useAlert } from '../contexts/AlertContext';

interface Matriz {
 Id: number;
 Descricao: string;
}

export default function MatrizAdmin() {
 const { showAlert } = useAlert();
 const [matrizes, setMatrizes] = useState<Matriz[]>([]);
 const [isLoading, setIsLoading] = useState(true);

 // Form state
 const [isEditing, setIsEditing] = useState(false);
 const [formData, setFormData] = useState<Matriz>({ Id: 0, Descricao: '' });
 const [originalId, setOriginalId] = useState<number | null>(null);

 // Instead of checking regular App user, we check the Superadmin token, 
 // since this component is embedded only inside SuperadminPage.
 const token = localStorage.getItem('superadmin_token') || '';

 const authHeaders = {
 'Content-Type': 'application/json',
 'Authorization': `Bearer ${token}`
 };

 const fetchMatrizes = async () => {
 setIsLoading(true);
 try {
 const res = await fetch('/api/matriz', { headers: authHeaders });
 const data = await res.json();
 if (data.success) {
 setMatrizes(data.data);
 } else {
 showAlert(data.message || 'Erro ao carregar matrizes', 'error');
 }
 } catch (error) {
 console.error(error);
 showAlert('Falha na comunica├º├úo com o servidor', 'error');
 } finally {
 setIsLoading(false);
 }
 };

 useEffect(() => {
 fetchMatrizes();
 }, []);

 const handleEdit = (matriz: Matriz) => {
 setIsEditing(true);
 setOriginalId(matriz.Id);
 setFormData({ ...matriz });
 };

 const handleCancel = () => {
 setIsEditing(false);
 setOriginalId(null);
 setFormData({ Id: 0, Descricao: '' });
 };

 const handleSave = async (e: React.FormEvent) => {
 e.preventDefault();

 if (!formData.Descricao) {
 showAlert('A Descri├º├úo ├® obrigat├│ria', 'warning');
 return;
 }

 try {
 if (originalId !== null) {
 // UPDATE
 const res = await fetch(`/api/matriz/${originalId}`, {
 method: 'PUT',
 headers: authHeaders,
 body: JSON.stringify({ Descricao: formData.Descricao })
 });
 const data = await res.json();
 if (data.success) {
