 {/* ÔöÇÔöÇ Cabe├ºalho ÔöÇÔöÇ */}
 <div className="px-5 py-3 border-b border-slate-100 flex items-center justify-between bg-white rounded-t-2xl shrink-0">
 <div className="flex items-center gap-2.5">
 <div className="p-2 bg-orange-100 text-orange-600 rounded-md shadow-sm"><ShieldAlert size={17} /></div>
 <div>
 <h3 className="text-sm font-black text-slate-800 leading-none">Gerar Pend├¬ncia (RNC)</h3>
