 )}

 {/* ÔöÇÔöÇ Linha 1: T├¡tulo + Subt├¡tulo ÔöÇÔöÇ */}
 <div className="grid grid-cols-2 gap-3">
 <div>
 <label className={labelCls}>T├¡tulo da Pend├¬ncia</label>
 <input type="text" value={rncForm.titulo}
 onChange={e => setRncForm((p: Record<string, unknown>) => ({...p, titulo: e.target.value.toUpperCase()}))}
 className={inputCls} placeholder="T├¡tulo..." />
 </div>
 <div>
 <label className={labelCls}>Subt├¡tulo / Detalhe</label>
 <input type="text" value={rncForm.subTitulo}
 onChange={e => setRncForm((p: Record<string, unknown>) => ({...p, subTitulo: e.target.value.toUpperCase()}))}
 className={inputCls} placeholder="Subt├¡tulo..." />
 </div>
 </div>

 {/* ÔöÇÔöÇ Linha 2: Descri├º├úo ÔöÇÔöÇ */}
 <div>
 <label className={labelCls}>Descri├º├úo da N├úo Conformidade *</label>
 <textarea value={rncForm.descricao}
 onChange={e => setRncForm((p: Record<string, unknown>) => ({...p, descricao: e.target.value.toUpperCase()}))}
 placeholder="Descreva o problema ou pend├¬ncia..."
 className={`${inputCls} min-h-[52px] resize-none`} />
 </div>

 {/* ÔöÇÔöÇ Linha 3: Processos + Setor + Respons├ível + Tipo + Data ÔöÇÔöÇ */}
 <div className="grid grid-cols-5 gap-3 items-end">
 {/* Processos Afetados */}
 <div className="col-span-2">
 <label className={labelCls}>Processos Afetados</label>
 <div className="grid grid-cols-3 gap-1.5 w-fit">
 {[
 { label: 'Corte', key: 'chkCorte', icon: Scissors },
 { label: 'Dobra', key: 'chkDobra', icon: Wrench },
 { label: 'Solda', key: 'chkSolda', icon: Flame },
 { label: 'Pintura', key: 'chkPintura', icon: Paintbrush },
 { label: 'Montagem', key: 'chkMontagem', icon: Settings2 }
 ].filter(proc => processosVisiveis.includes(proc.label.toLowerCase())).map(proc => (
 <label key={proc.key} className={`flex items-center gap-1 px-2 py-1 rounded-lg border cursor-pointer transition-all text-[9px] font-black uppercase ${rncForm[proc.key as keyof RncFormData] ? 'bg-orange-50 border-orange-400 text-orange-700' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'}`}>
 <input type="checkbox" className="hidden"
 checked={!!rncForm[proc.key as keyof RncFormData]}
 onChange={e => setRncForm((p: Record<string, unknown>) => ({...p, [proc.key]: e.target.checked}))} />
 <proc.icon size={9} />{proc.label}
 </label>
 ))}
 </div>
 </div>
 {/* Setor */}
 <div>
 <label className={labelCls}>Setor Respons├ível *</label>
 <select value={rncForm.setor} onChange={e => setRncForm((p: Record<string, unknown>) => ({...p, setor: e.target.value}))} className={selectCls}>
 {SECTORS.filter(s => processosVisiveis.includes(s.k.toLowerCase())).map(s => <option key={s.k} value={s.k}>{s.k}</option>)}
 </select>
 </div>
 {/* Colaborador */}
 <div>
 <label className={labelCls}>Colaborador *</label>
 <select value={rncForm.usuario} onChange={e => setRncForm((p: Record<string, unknown>) => ({...p, usuario: e.target.value}))} className={selectCls}>
 <option value="">Selecione...</option>
 {usuarios.map(u => <option key={u.IdUsuario ?? u.id ?? u.NomeCompleto} value={u.NomeCompleto ?? u.label}>{u.NomeCompleto ?? u.label}</option>)}
 </select>
 </div>
 {/* Tipo + Data lado a lado */}
 <div className="flex flex-col gap-1.5">
 <div>
 <label className={labelCls}>Tipo</label>
 <select value={rncForm.tipoTarefa} onChange={e => setRncForm((p: Record<string, unknown>) => ({...p, tipoTarefa: e.target.value}))} className={selectCls}>
 <option value="">Selecione...</option>
 {tipostarefa.map(t => <option key={t.IdTipoTarefa ?? t.id} value={t.TipoTarefa ?? t.label}>{t.TipoTarefa ?? t.label}</option>)}
 </select>
 </div>
 <div>
 <label className={labelCls}>Previs├úo</label>
 <input type="date" value={rncForm.dataExec}
 onChange={e => setRncForm((p: Record<string, unknown>) => ({...p, dataExec: e.target.value}))}
 className={inputCls} />
 </div>
 </div>
 </div>

 {/* ÔöÇÔöÇ Grid de Pend├¬ncias existentes ÔöÇÔöÇ */}
 {codMatFabricante && (
 <PainelPendenciasPlanoCorte 
 codMatFabricante={codMatFabricante} 
 usuarios={usuarios} 
 setores={SECTORS.filter(s => processosVisiveis.includes(s.k.toLowerCase())).map(s => s.k)}
 refreshKey={refreshKey}
 />
 )}
 </div>

 {/* ÔöÇÔöÇ Rodap├® ÔöÇÔöÇ */}
 <div className="px-5 py-3 bg-slate-50 border-t border-slate-100 flex items-center justify-between rounded-b-2xl shrink-0">
 <p className="text-[9px] text-slate-400">* Ap├│s salvar, o formul├írio ├® limpo e o grid atualizado automaticamente.</p>
 <div className="flex items-center gap-2">
 <button onClick={() => setActionModal(null)}
 className="px-4 py-2 text-[11px] font-bold text-slate-500 hover:bg-slate-200 rounded-md transition-all">
 Fechar
 </button>
 <button onClick={salvarNovaRnc}
 disabled={isSaving || !rncForm.descricao.trim()}
 className="px-5 py-2 bg-orange-500 hover:bg-orange-600 text-white rounded-md shadow-md shadow-orange-500/30 transition-all disabled:opacity-50 flex items-center gap-1.5 font-black text-[11px]">
 {isSaving ? <Loader2 className="animate-spin" size={14} /> : <ShieldAlert size={14} />}
 Gerar RNC
 </button>
 </div>
 </div>
 </div>
 </div>
 );
}
