export default function MontagemPlanoCortePage() {
 const { token } = useAuth();
 const { addToast } = useToast();
 const appConfig = useAppConfig();
 const filtroAtivo = appConfig.planoCorteFiltroDC || 'corte';
 const [refreshPlanos, setRefreshPlanos] = useState(0);

 // --- Estados RNC elevados para o nivel da pagina ---
 const [pageActionModal, setPageActionModal] = useState<null | 'addRnc'>(null);
 const [pageRncRefreshKey, setPageRncRefreshKey] = useState(0);
 const [pageItemSelecionado, setPageItemSelecionado] = useState<unknown>(null);
 const [pageIsSaving, setPageIsSaving] = useState(false);
 const [pageMsg, setPageMsg] = useState<{ t: 's' | 'e'; m: string } | null>(null);
 const [pageUsuarios, setPageUsuarios] = useState<unknown[]>([]);
 const [pageTipostarefa, setPageTipostarefa] = useState<unknown[]>([]);
 const [pageRncForm, setPageRncForm] = useState<RncFormData>({
 idRnc: 0, projeto: '', idProjeto: '', tag: '', idTag: '', descTag: '',
 cliente: '', codMatFabricante: '', descricao: '', setor: 'Corte', usuario: '',
 tipoTarefa: '', dataExec: new Date().toISOString().split('T')[0],
 titulo: '', subTitulo: '', espessura: '', materialSW: '',
 chkCorte: false, chkDobra: false, chkSolda: false, chkPintura: false, chkMontagem: false
 });

 useEffect(() => {
 const loadConfig = async () => {
 try {
 const [uRes, tRes] = await Promise.all([
 fetch('/api/config/usuarios', { headers: { 'Authorization': `Bearer ${token}` } }),
 fetch('/api/config/tipostarefa', { headers: { 'Authorization': `Bearer ${token}` } })
 ]);
 const [uData, tData] = await Promise.all([uRes.json(), tRes.json()]);
 if (uData.success) setPageUsuarios(uData.usuarios || []);
 if (tData.success) setPageTipostarefa(tData.tipostarefa || []);
 } catch (e) { console.error('Erro ao carregar config RNC pagina:', e); }
 };
 loadConfig();
 }, [token]);

 const handlePageGerarRnc = (item: Record<string, unknown>) => {
 setPageItemSelecionado(item);
 setPageRncForm({
 idRnc: 0,
 projeto: item.Projeto || '',
 idProjeto: item.IdProjeto || '',
 tag: item.Tag || '',
 idTag: item.IdTag || '',
 descTag: item.DescTag || '',
 cliente: item.DescEmpresa || '',
 codMatFabricante: item.CodMatFabricante || '',
 descricao: '',
 setor: 'Corte',
 usuario: '',
 tipoTarefa: '',
 dataExec: new Date().toISOString().split('T')[0],
 titulo: item.DescResumo || '',
 subTitulo: item.DescDetal || '',
 espessura: item.Espessura || '',
 materialSW: item.MaterialSW || '',
 chkCorte: item.txtCorte === '1',
 chkDobra: item.txtDobra === '1',
 chkSolda: item.TxtSolda === '1' || item.txtSolda === '1',
 chkPintura: item.txtPintura === '1',
 chkMontagem: item.TxtMontagem === '1' || item.txtMontagem === '1'
 });
 setPageMsg(null);
 setPageActionModal('addRnc');
 };

 const handlePageSalvarRnc = async () => {
 if (!pageRncForm.setor || !pageRncForm.usuario || !pageRncForm.descricao) {
 setPageMsg({ t: 'e', m: 'Preencha todos os campos obrigat├│rios.' });
 return;
 }
 setPageIsSaving(true); setPageMsg(null);
 try {
 const payload = {
 idOrdemServicoItem: pageItemSelecionado?.IdOrdemServicoItem,
 idOrdemServico: pageItemSelecionado?.IdOrdemServico,
 idProjeto: pageRncForm.idProjeto,
 projeto: pageRncForm.projeto,
 idTag: pageRncForm.idTag,
 tag: pageRncForm.tag,
 descTag: pageRncForm.descTag,
 descEmpresa: pageRncForm.cliente,
 codMatFabricante: pageRncForm.codMatFabricante,
 espessura: pageRncForm.espessura,
 materialSW: pageRncForm.materialSW,
 txtCorte: pageRncForm.chkCorte ? '1' : '',
 txtDobra: pageRncForm.chkDobra ? '1' : '',
 txtSolda: pageRncForm.chkSolda ? '1' : '',
 txtPintura: pageRncForm.chkPintura ? '1' : '',
 txtMontagem: pageRncForm.chkMontagem ? '1' : '',
 descricaoPendencia: pageRncForm.descricao,
 setorResponsavel: pageRncForm.setor,
 usuarioResponsavel: pageRncForm.usuario,
 titulo: pageRncForm.titulo,
 subTitulo: pageRncForm.subTitulo,
 tipoRnc: pageRncForm.tipoTarefa,
 dataExecucao: pageRncForm.dataExec,
 usuarioCriacao: 'Sistema',
 descProjeto: pageRncForm.projeto,
 origemPendencia: 'PLANODECORTE',
 acao: 'SALVAR'
 };
 const res = await fetch('/api/producao/pendencia', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
 body: JSON.stringify(payload)
 });
 const result = await res.json();
 if (result.success) {
 setPageMsg({ t: 's', m: 'Pend├¬ncia (RNC) gerada com sucesso! Gere outra ou feche o painel.' });
 addToast({ type: 'success', title: 'RNC Gerada', message: 'Pend├¬ncia registrada com sucesso!' });
 // Limpar campos de conte├║do, manter dados do item
 setPageRncForm(f => ({
 ...f,
 titulo: '', subTitulo: '', descricao: '',
 chkCorte: false, chkDobra: false, chkSolda: false, chkPintura: false, chkMontagem: false,
 }));
 setPageRncRefreshKey(k => k + 1);
 } else {
 setPageMsg({ t: 'e', m: result.message || 'Erro ao salvar' });
 }
 } catch (e: unknown) {
 setPageMsg({ t: 'e', m: e.message });
 } finally {
 setPageIsSaving(false);
 }
 };

 return (
 <div className="flex flex-col h-[calc(100vh-8rem)] bg-[#f1f5f9] text-slate-800">
 <div className="shrink-0 bg-white border-b border-slate-200 shadow-sm px-5 py-3">
 <div className="flex items-center justify-between">
 <div className="flex items-center gap-3">
 <div className="h-10 w-10 bg-blue-100 text-[#32423D] rounded-md flex items-center justify-center shadow-sm shrink-0"><Scissors size={22} /></div>
 <div>
 
 <p className="text-[11px] text-slate-500 mt-0.5">Selecione itens de OS e inclua no plano de corte</p>
 </div>
 </div>
 <div className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold border-2 ${filtroAtivo === 'chaparia' ? 'bg-purple-50 border-purple-300 text-purple-700' : 'bg-[#E0E800]/20 border-blue-300 text-[#32423D]'}`}>
 {filtroAtivo === 'chaparia' ? <FileType2 size={14} /> : <SplitSquareHorizontal size={14} />}
 {filtroAtivo === 'chaparia' ? 'Desenho Chaparia' : 'Setor Corte'}
 <span className="text-[9px] opacity-60 ml-1">(via Configuracao)</span>
 </div>
 </div>
 </div>
 <div className="flex-1 overflow-hidden grid grid-cols-2 gap-3 p-3">
 <PainelItensOS
 tipoFiltro={filtroAtivo}
 onPlanosChange={() => setRefreshPlanos(v => v + 1)}
 onGerarRnc={handlePageGerarRnc}
 />
 <PainelPlanosCorte
 refreshTrigger={refreshPlanos}
 externalOnGerarRnc={handlePageGerarRnc}
 />
 </div>

 {/* Modal RNC centralizado no nivel da pagina - acessivel por ambos os paineis */}
 {pageActionModal === 'addRnc' && (
 <ModalRnc
 rncForm={pageRncForm}
 setRncForm={setPageRncForm}
 isSaving={pageIsSaving}
 msg={pageMsg}
 setActionModal={setPageActionModal}
 salvarNovaRnc={handlePageSalvarRnc}
 usuarios={pageUsuarios}
 tipostarefa={pageTipostarefa}
 codMatFabricante={pageRncForm.codMatFabricante}
 refreshKey={pageRncRefreshKey}
 />
 )}
 </div>
 );
}

import { useState, useEffect } from 'react';
import { Search, Loader2, FileSearch, X, FileText, Box } from 'lucide-react';
const API_BASE = '/api';

interface SetorItem {
 idSetor: number;
 Setor: string;
 DataLiberada: string;
 NomeLimpo: string; // Ex: 'txtCorte' -> 'Corte'
 colTxt: string;
 colSt: string;
}

interface OSI {
 IdOrdemServicoItem: number | string;
 IdOrdemServico: number | string;
 Projeto: string;
 Tag: string;
 idplanodecorte?: string | null;
 QtdeTotal: number;
 CodMatFabricante: string;
 DescResumo: string;
 DescDetal: string;
 Espessura: string;
 MaterialSW: string;
 Liberado_Engenharia: string;
 Data_Liberacao_Engenharia: string;
 OrdemServicoItemFinalizado: string;
 EnderecoArquivo: string;
 // Dynamic Setor columns will be accessible dynamically via bracket notation
 [key: string]: unknown;
}

export default function PesquisarDesenho() {
 const [loading, setLoading] = useState(false);
 const [pesquisado, setPesquisado] = useState(false);
 const [error, setError] = useState<string | null>(null);

 const [items, setItems] = useState<OSI[]>([]);
 const [setoresAtivos, setSetoresAtivos] = useState<SetorItem[]>([]);

 // Filtros
 const [filProjeto, setFilProjeto] = useState('');
 const [filTag, setFilTag] = useState('');
 const [filCodMat, setFilCodMat] = useState('');
 const [filDescResumo, setFilDescResumo] = useState('');
 const [filDescDetal, setFilDescDetal] = useState('');
 const [filEspessura, setFilEspessura] = useState('');
 const [filMaterialSW, setFilMaterialSW] = useState('');

 const hasFilters = filProjeto || filTag || filCodMat || filDescResumo || filDescDetal || filEspessura || filMaterialSW;

 const limparFiltros = () => {
 setFilProjeto('');
 setFilTag('');
 setFilCodMat('');
 setFilDescResumo('');
 setFilDescDetal('');
 setFilEspessura('');
 setFilMaterialSW('');
 setItems([]);
 setPesquisado(false);
 };

 const fetchDesenhos = async () => {
 setLoading(true);
 setError(null);
 try {
 const url = new URL(`${window.location.origin}${API_BASE}/pesquisar-desenho`);
 if (filProjeto) url.searchParams.append('projeto', filProjeto.trim());
 if (filTag) url.searchParams.append('tag', filTag.trim());
 if (filCodMat) url.searchParams.append('codMat', filCodMat.trim());
 if (filDescResumo) url.searchParams.append('descResumo', filDescResumo.trim());
 if (filDescDetal) url.searchParams.append('descDetal', filDescDetal.trim());
 if (filEspessura) url.searchParams.append('espessura', filEspessura.trim());
 if (filMaterialSW) url.searchParams.append('material', filMaterialSW.trim());

 const res = await fetch(url.toString(), {
 headers: {
 'Authorization': `Bearer ${localStorage.getItem('sinco_token')}`
 }
 });
 const data = await res.json();
 
 if (data.success) {
 setItems(data.data);
 setSetoresAtivos(data.setores);
 setPesquisado(true);
 } else {
 setError(data.message || 'Erro ao buscar dados.');
 }
 } catch (err) {
 console.error(err);
 setError('Erro de comunica├º├úo com o servidor.');
 } finally {
 setLoading(false);
 }
 };

 // Load initial data
 useEffect(() => {
 fetchDesenhos();
 }, []);

 // Helper para extrair a situa├º├úo de cada setor
 const getSetorStatusClass = (valor: string | number) => {
 const strVal = String(valor).toUpperCase();
 if (strVal === 'S' || strVal === '1') return 'bg-emerald-100 text-emerald-800 border-emerald-300';
 if (strVal === 'N' || strVal === '0' || !valor || strVal.includes('N├âO')) return 'bg-slate-100 text-slate-500 border-slate-200';
 if (strVal.includes('%') || parseFloat(strVal) > 0) return 'bg-amber-100 text-amber-800 border-amber-300';
 
 // Default text fallback
 if (valor && strVal !== '') return 'bg-[#E0E800]/30 text-[#32423D] border-blue-200';

 return 'text-slate-400';
 };

 const abrirArquivoLocal = async (caminho: string, tipo: '3d' | 'pdf' | 'dxf') => {
 if (!caminho || caminho.trim() === '') {
 alert("Endere├ºo do arquivo n├úo encontrado no sistema ou n├úo atrelado a este item.");
 return;
 }
 try {
 const url = new URL(`${window.location.origin}${API_BASE}/controle-expedicao/abrir-arquivo`);
 url.searchParams.append('caminho', String(caminho));
 url.searchParams.append('tipo', tipo);
 const res = await fetch(url.toString(), {
 headers: { 'Authorization': `Bearer ${localStorage.getItem('sinco_token')}` }
 });
 const data = await res.json();
 if (!data.success) {
 alert(data.message || 'Erro ao abrir arquivo.');
 }
 } catch {
 alert('Erro de comunica├º├úo ao abrir arquivo.');
 }
 };

 return (
 <div className="flex flex-col flex-1 min-h-0 bg-[#fafbfc] animate-in fade-in zoom-in-95 duration-300 h-full flex flex-col min-h-0">
 {/* Header / Filtros */}
 <div className="bg-white p-3 rounded-md shadow-[0_2px_10px_-3px_rgba(6,81,237,0.1)] border border-slate-200 mb-2 shrink-0">
 <div className="flex justify-between items-center mb-2">
 <h2 className="text-xs font-bold text-slate-700 flex items-center gap-2">
 <FileSearch className="text-[#32423D]" size={16} />
 Pesquisar Desenho
 </h2>
 </div>
 
 <div className="grid grid-cols-2 lg:grid-cols-4 gap-2">
 <div className="relative flex items-center w-full">
 <input type="text" placeholder="Projeto" value={filProjeto} onChange={e => setFilProjeto(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter') fetchDesenhos(); }} className="w-full text-[11px] px-2 py-1 border border-slate-300 rounded focus:outline-none focus:border-[#32423D] bg-white" />
 {filProjeto && (
 <button onClick={() => setFilProjeto('')} className="absolute right-1.5 text-slate-400 hover:text-red-500 transition-colors bg-transparent border-none" title="Limpar">
 <X size={14} />
 </button>
 )}
 </div>
 <div className="relative flex items-center w-full">
 <input type="text" placeholder="Tag" value={filTag} onChange={e => setFilTag(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter') fetchDesenhos(); }} className="w-full text-[11px] px-2 py-1 border border-slate-300 rounded focus:outline-none focus:border-[#32423D] bg-white" />
 {filTag && (
 <button onClick={() => setFilTag('')} className="absolute right-1.5 text-slate-400 hover:text-red-500 transition-colors bg-transparent border-none" title="Limpar">
 <X size={14} />
 </button>
 )}
 </div>
 <div className="relative flex items-center w-full">
 <input type="text" placeholder="C├│d. Mat. Fabricante" value={filCodMat} onChange={e => setFilCodMat(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter') fetchDesenhos(); }} className="w-full text-[11px] px-2 py-1 border border-slate-300 rounded focus:outline-none focus:border-[#32423D] bg-white" />
 {filCodMat && (
 <button onClick={() => setFilCodMat('')} className="absolute right-1.5 text-slate-400 hover:text-red-500 transition-colors bg-transparent border-none" title="Limpar">
 <X size={14} />
 </button>
 )}
 </div>
 <div className="relative flex items-center w-full">
