 )}
 <button onClick={fetchDesenhos} disabled={loading} className="px-4 py-1.5 flex items-center justify-center gap-2 bg-emerald-100 border border-emerald-200 text-emerald-800 rounded shadow-sm text-[11px] font-bold hover:bg-emerald-200 transition-colors disabled:opacity-50 flex-1 lg:flex-none">
 {loading ? <Loader2 size={14} className="animate-spin" /> : <Search size={14} />}
 PESQUISAR
 </button>
 </div>
 </div>
 </div>

 {/* Grid */}
 <div className="flex-1 bg-white border border-slate-200 rounded-md overflow-hidden flex flex-col min-h-0 shadow-sm relative">
 {error && <div className="bg-red-50 text-red-700 p-3 text-xs font-bold border-b border-red-100">{error}</div>}
 
 {loading && (
 <div className="absolute inset-0 bg-white/50 z-10 flex items-center justify-center">
 <Loader2 className="animate-spin text-[#32423D]" size={32} />
 </div>
 )}

 <div className="table-container">
 <table className="w-full text-left text-[11px] whitespace-nowrap">
 <thead className="bg-[#567469] text-white bg-[#567469] text-white bg-[#567469] text-white font-bold uppercase tracking-wider text-[9px] sticky top-0 z-20 shadow-[0_1px_2px_rgba(0,0,0,0.05)]">
 <tr>
 <th className="px-2 py-1.5 bg-[#f8fafc] sticky left-0 z-30 shadow-[1px_0_0_rgba(0,0,0,0.05)]">A├º├Áes</th>
 <th className="px-2 py-1.5">Projeto</th>
 <th className="px-2 py-1.5">Tag</th>
 <th className="px-2 py-1.5">OS</th>
 <th className="px-2 py-1.5">Item</th>
 <th className="px-2 py-1.5">Plano Corte</th>
 <th className="px-2 py-1.5 text-center">Qtde Total</th>
 <th className="px-2 py-1.5">C├│d. Mat. Fab.</th>
