 <th className="px-2 py-1.5">Data Lib.</th>
 <th className="px-2 py-1.5 text-center">Finalizado</th>
 
 {/* Dynamic Setores Columns */}
 {setoresAtivos.map(setor => (
 <th key={setor.idSetor} className="px-2 py-1.5 text-center border-l border-white/20 text-[#4c5561]" title={setor.Setor}>
 {setor.NomeLimpo}
 </th>
 ))}

 <th className="px-2 py-1.5">Desc. Resumo</th>
 <th className="px-2 py-1.5 max-w-[200px]">Desc. Detalhe</th>
 </tr>
 </thead>
 <tbody className="divide-y divide-slate-100">
 {items.length === 0 && !loading && pesquisado && (
 <tr>
 <td colSpan={15 + setoresAtivos.length} className="px-4 py-8 text-center text-slate-400 font-medium">
 Nenhum registro encontrado para a pesquisa.
 </td>
 </tr>
 )}
 {items.length === 0 && !pesquisado && (
 <tr>
 <td colSpan={15 + setoresAtivos.length} className="px-4 py-8 text-center text-slate-400 font-medium flex-col items-center justify-center">
 <FileSearch size={32} className="mx-auto mb-2 opacity-30" />
 Utilize os filtros acima para pesquisar.
 </td>
 </tr>
 )}

 {items.map(item => (
 <tr key={`osi-${item.IdOrdemServicoItem}`} className="hover:bg-[#E0E800]/10 transition-colors">
 <td className="px-2 py-1 bg-white sticky left-0 z-10 shadow-[1px_0_0_rgba(0,0,0,0.05)] flex gap-1 items-center">
 {/* 1 - Abrir Desenho 3D */}
 <button onClick={() => abrirArquivoLocal(item.EnderecoArquivo, '3d')} className="p-1 text-slate-500 hover:text-[#32423D] hover:bg-[#E0E800]/10 rounded" title="1 - Abrir Desenho 3D">
 <Box size={14} />
 </button>
 {/* 2 - Abrir Desenho PDF */}
 <button onClick={() => abrirArquivoLocal(item.EnderecoArquivo, 'pdf')} className="p-1 text-slate-500 hover:text-red-600 hover:bg-red-50 rounded" title="2 - Abrir Desenho PDF">
 <FileText size={14} />
 </button>
 {/* 3 - Abrir Desenho DXF */}
 <button onClick={() => abrirArquivoLocal(item.EnderecoArquivo, 'dxf')} className="p-1 text-slate-500 hover:text-cyan-700 hover:bg-cyan-50 rounded font-mono text-[9px] font-bold" title="3 - Abrir Desenho DXF">
 DXF
 </button>
 </td>
 
 <td className="px-2 py-1 font-bold text-slate-700">{item.Projeto || ''}</td>
 <td className="px-2 py-1 font-bold text-[#32423D]">{item.Tag || ''}</td>
 <td className="px-2 py-1 font-mono text-slate-600">{item.IdOrdemServico || ''}</td>
 <td className="px-2 py-1 font-mono text-slate-600">{item.IdOrdemServicoItem || ''}</td>
 <td className="px-2 py-1 font-mono text-purple-700">{item.idplanodecorte || '-'}</td>
 <td className="px-2 py-1 text-center font-bold text-slate-800 bg-slate-50/50">{item.QtdeTotal || 0}</td>
 <td className="px-2 py-1 font-mono text-slate-600 truncate max-w-[100px]" title={item.CodMatFabricante}>{item.CodMatFabricante || '-'}</td>
 <td className="px-2 py-1 text-slate-600">{item.Espessura || '-'}</td>
 <td className="px-2 py-1 text-slate-600 max-w-[100px] truncate" title={item.MaterialSW}>{item.MaterialSW || '-'}</td>
 <td className="px-2 py-1">
 {item.Liberado_Engenharia === 'SIM' 
 ? <span className="px-1.5 py-0.5 bg-emerald-100 text-emerald-700 rounded text-[9px] font-bold">SIM</span> 
 : <span className="px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded text-[9px] font-bold">N├âO</span>}
 </td>
 <td className="px-2 py-1 text-slate-500 font-mono text-[10px]">{item.Data_Liberacao_Engenharia || '-'}</td>
 <td className="px-2 py-1 text-center">
 {item.OrdemServicoItemFinalizado === 'SIM' 
 ? <span className="px-1.5 py-0.5 bg-[#E0E800]/40 text-[#32423D] rounded text-[9px] font-bold">SIM</span> 
 : <span className="px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded text-[9px] font-bold">N├âO</span>}
 </td>

 {/* Mapeamento Din├ómico de Setores */}
 {setoresAtivos.map(setor => {
 const colNameLower = setor.colTxt.toLowerCase();
 const colStatusLower = setor.colSt.toLowerCase();
 
 // Busca case-insensitive
 const keyOriginal = Object.keys(item).find(k => k.toLowerCase() === colNameLower);
 const keyStatus = Object.keys(item).find(k => k.toLowerCase() === colStatusLower);

 const valOriginal = keyOriginal ? item[keyOriginal] : '';
 const valStatus = keyStatus ? item[keyStatus] : '';
 
 const displayVal = valStatus ? `${valOriginal} (${valStatus})` : valOriginal;

 return (
 <td key={setor.idSetor} className="px-2 py-1 text-center border-l border-slate-100">
 {displayVal ? (
 <span className={`px-2 py-0.5 rounded border text-[9px] font-bold inline-block text-center min-w-[30px] ${getSetorStatusClass(valOriginal)}`}>
 {displayVal}
 </span>
 ) : <span className="text-slate-300">-</span>}
 </td>
 )
 })}

 <td className="px-2 py-1 text-[10px] text-slate-600 truncate max-w-[150px]" title={item.DescResumo}>{item.DescResumo || '-'}</td>
 <td className="px-2 py-1 text-[10px] text-slate-500 truncate max-w-[200px]" title={item.DescDetal}>{item.DescDetal || '-'}</td>

 </tr>
 ))}
 </tbody>
 </table>
 </div>
 </div>

 </div>
 );
}

import { useState, useEffect, useMemo } from 'react';
import { Search, Loader2, Calendar, LayoutGrid, CheckCircle2, Circle, Target, Hash, ArrowLeft, X, XCircle } from 'lucide-react';
import { useAppConfig } from '../contexts/AppConfigContext';

interface PlanejamentoItem {
 IdOrdemServicoItem: number;
 IdOrdemServico: number;
 OSDescricao?: string;
 Projeto: string;
 Tag: string;
 CodMatFabricante: string;
 DescResumo: string;
 Setor: string;
 PlanejadoInicio: string;
 PlanejadoFim: string;
 QtdeTotal: number;
 QtdeExecutada: number;
}

export default function PlanejamentoProducao({ fromGlobal, onBack }: { fromGlobal?: boolean, onBack?: () => void }) {
 const { processosVisiveis, maxRegistros } = useAppConfig();
 const today = new Date().toISOString().split('T')[0];
 
 const [planInicioDe, setPlanInicioDe] = useState(today);
 const [planInicioAte, setPlanInicioAte] = useState(today);
 const [planFimDe, setPlanFimDe] = useState('');
 const [planFimAte, setPlanFimAte] = useState('');
 const [setor, setSetor] = useState('todos');
 const [osPesquisa, setOsPesquisa] = useState('');
 
 const [itens, setItens] = useState<PlanejamentoItem[]>([]);
 const [loading, setLoading] = useState(false);
 const [error, setError] = useState<string | null>(null);

 // Efeito para esconder o cabe├ºalho global quando este componente montar
 useEffect(() => {
 if (!fromGlobal) {
 const title = document.getElementById('main-page-title');
 const subtitle = title?.nextElementSibling;
 if (title) title.style.display = 'none';
 if (subtitle) (subtitle as HTMLElement).style.display = 'none';

 return () => {
 if (title) title.style.display = '';
 if (subtitle) (subtitle as HTMLElement).style.display = '';
 };
 }
 }, [fromGlobal]);

 const formatData = (d: string) => {
 if (!d) return '-';
 if (d.includes('-')) {
 const p = d.split('-');
 return `${p[2]}/${p[1]}/${p[0]}`;
 }
 return d;
 };

 const fetchPlanejamento = async (useFallbackToday = false) => {
 setLoading(true);
 setError(null);
 
 const qPlanIniDe = useFallbackToday ? today : planInicioDe;
 const qPlanIniAte = useFallbackToday ? today : planInicioAte;
 const qPlanFimDe = useFallbackToday ? '' : planFimDe;
 const qPlanFimAte = useFallbackToday ? '' : planFimAte;
 const qSetor = useFallbackToday ? 'todos' : setor;
 const qOs = useFallbackToday ? '' : osPesquisa;

 try {
 const res = await fetch(`/api/apontamento/planejamento/diario?planInicioDe=${qPlanIniDe}&planInicioAte=${qPlanIniAte}&planFimDe=${qPlanFimDe}&planFimAte=${qPlanFimAte}&setor=${qSetor}&os=${encodeURIComponent(qOs)}&limit=${maxRegistros}`);
 const json = await res.json();
 if (json.success) {
 if (json.data.length === 0 && !useFallbackToday && (osPesquisa || planInicioDe !== today || planInicioAte !== today || planFimDe || planFimAte)) {
 // Fallback to today if search yields nothing
 addTemporaryMessage("Nenhum resultado para a pesquisa. Exibindo totais de hoje.");
 fetchPlanejamento(true);
 } else {
 setItens(json.data);
 }
 } else {
 setError(json.message || 'Erro ao carregar dados');
 }
 } catch {
 setError('Erro de conex├úo com o servidor');
 } finally {
 setLoading(false);
 }
 };

 const [fallbackMsg, setFallbackMsg] = useState('');
 const addTemporaryMessage = (msg: string) => {
 setFallbackMsg(msg);
 setTimeout(() => setFallbackMsg(''), 5000);
 };

 useEffect(() => {
 fetchPlanejamento(true);
 }, []);

 // Calcula os totais do resultado atual
 const { totalExecutar, totalExecutado } = useMemo(() => {
 let executar = 0;
 let executado = 0;
 itens.forEach(item => {
 executar += Number(item.QtdeTotal) || 0;
 executado += Number(item.QtdeExecutada) || 0;
 });
 return { totalExecutar: executar, totalExecutado: executado };
 }, [itens]);

 const percentual = totalExecutar > 0 ? Math.round((totalExecutado / totalExecutar) * 100) : 0;

 // Agrupa por OS
 const groupedByOS = useMemo(() => {
 const groups: Record<number, PlanejamentoItem[]> = {};
 itens.forEach(item => {
 if (!groups[item.IdOrdemServico]) groups[item.IdOrdemServico] = [];
 groups[item.IdOrdemServico].push(item);
 });
 return groups;
 }, [itens]);

 return (
 <div className={`h-full flex flex-col ${fromGlobal ? 'p-2 md:p-3 lg:p-4' : ''}`}>
 {/* Header and Filters (Compact Layout) */}
 <div className="bg-white dark:bg-card border-b border-gray-100 p-2 shadow-sm shrink-0 z-10 flex flex-col gap-2">
 <div className="flex items-center gap-3">
 {!fromGlobal && onBack && (
 <button
 onClick={onBack}
 className="flex items-center justify-center p-1.5 rounded-md bg-gray-100 text-gray-600 hover:bg-gray-200 hover:text-[#32423D] transition-colors"
 title="Voltar para Mapa"
 >
 <ArrowLeft size={18} />
 </button>
 )}
 <div>
 <h1 className="text-lg font-black text-[#32423D] flex items-center gap-2 m-0 leading-none">
 <Calendar className="w-5 h-5 text-[#E0E800]" />
 Dashboard de Planejamento
 <span className="text-xs font-semibold text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full ml-2">Limite: {maxRegistros}</span>
 </h1>
 </div>
 </div>

 <div className="grid grid-cols-1 md:grid-cols-6 gap-2 items-end bg-gray-50/50 p-2 rounded-md border border-gray-100">
 {/* OS ou Descri├º├úo */}
 <div className="md:col-span-2">
 <label className="block text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-1.5">OS ou Descri├º├úo</label>
 <div className="relative">
 <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
 <input 
 type="text" 
 placeholder="N┬║ da OS ou Texto"
 value={osPesquisa} 
 onChange={e => setOsPesquisa(e.target.value)} 
 className="w-full pl-9 pr-8 py-2.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-[#E0E800]/50 outline-none transition-all shadow-sm" 
 />
 {osPesquisa && (
 <button onClick={() => setOsPesquisa('')} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-400 hover:text-red-500 transition-colors" title="Limpar">
 <X size={14} />
 </button>
 )}
 </div>
 </div>

 {/* PLAN. IN├ìCIO (DE) ÔÇö DESTACADO */}
 <div>
 <label className="block text-[11px] font-bold text-amber-600 uppercase tracking-wider mb-1.5 flex items-center gap-1">
 <Calendar size={11} className="text-amber-500" />
 Plan. In├¡cio (De)
 </label>
 <div className="relative">
 <input
 type="date"
 value={planInicioDe}
 onChange={e => setPlanInicioDe(e.target.value)}
 className="w-full px-3 py-2.5 text-[13px] border-2 border-amber-400 rounded-lg shadow-sm focus:ring-2 focus:ring-amber-400/50 outline-none transition-all bg-amber-50 font-semibold text-amber-800"
 />
 {planInicioDe && (
 <button onClick={() => setPlanInicioDe('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-amber-400 hover:text-red-500 transition-colors" title="Limpar">
 <X size={13} />
 </button>
 )}
 </div>
 </div>

 {/* PLAN. IN├ìCIO (AT├ë) ÔÇö DESTACADO */}
 <div>
 <label className="block text-[11px] font-bold text-amber-600 uppercase tracking-wider mb-1.5 flex items-center gap-1">
 <Calendar size={11} className="text-amber-500" />
 Plan. In├¡cio (At├®)
 </label>
 <div className="relative">
 <input
 type="date"
 value={planInicioAte}
 onChange={e => setPlanInicioAte(e.target.value)}
 className="w-full px-3 py-2.5 text-[13px] border-2 border-amber-400 rounded-lg shadow-sm focus:ring-2 focus:ring-amber-400/50 outline-none transition-all bg-amber-50 font-semibold text-amber-800"
 />
 {planInicioAte && (
 <button onClick={() => setPlanInicioAte('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-amber-400 hover:text-red-500 transition-colors" title="Limpar">
 <X size={13} />
 </button>
 )}
 </div>
 </div>

 {/* Plan. Fim (De) */}
 <div>
 <label className="block text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-1.5">Plan. Fim (De)</label>
 <div className="relative">
 <input
 type="date"
 value={planFimDe}
 onChange={e => setPlanFimDe(e.target.value)}
 className="w-full px-3 py-2.5 text-[13px] border border-gray-200 rounded-lg shadow-sm focus:ring-2 focus:ring-[#E0E800]/50 outline-none transition-all"
 />
 {planFimDe && (
 <button onClick={() => setPlanFimDe('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-400 hover:text-red-500 transition-colors" title="Limpar">
 <X size={13} />
 </button>
 )}
 </div>
 </div>

 {/* Plan. Fim (At├®) */}
 <div>
 <label className="block text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-1.5">Plan. Fim (At├®)</label>
 <div className="relative">
 <input
 type="date"
 value={planFimAte}
 onChange={e => setPlanFimAte(e.target.value)}
 className="w-full px-3 py-2.5 text-[13px] border border-gray-200 rounded-lg shadow-sm focus:ring-2 focus:ring-[#E0E800]/50 outline-none transition-all"
 />
 {planFimAte && (
 <button onClick={() => setPlanFimAte('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-400 hover:text-red-500 transition-colors" title="Limpar">
 <X size={13} />
 </button>
 )}
 </div>
 </div>

 {/* Setor */}
 <div className="md:col-span-3">
 <label className="block text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-1.5">Setor</label>
 <select value={setor} onChange={e => setSetor(e.target.value)} className="w-full px-3 py-2.5 text-sm border border-gray-200 rounded-lg shadow-sm focus:ring-2 focus:ring-[#E0E800]/50 outline-none transition-all appearance-none bg-white">
 <option value="todos">Todos os Setores</option>
 {processosVisiveis.map(p => (
 <option key={p} value={p}>{p.charAt(0).toUpperCase() + p.slice(1)}</option>
 ))}
 </select>
 </div>

 {/* Bot├Áes: Limpar Todos + Buscar */}
 <div className="md:col-span-3 flex gap-2">
 {(osPesquisa || planInicioDe || planInicioAte || planFimDe || planFimAte || setor !== 'todos') && (
 <button
 onClick={() => {
 setOsPesquisa('');
 setPlanInicioDe(today);
 setPlanInicioAte(today);
 setPlanFimDe('');
 setPlanFimAte('');
 setSetor('todos');
 }}
 className="flex items-center gap-1.5 px-3 py-2.5 rounded-lg border border-red-200 bg-red-50 text-red-600 hover:bg-red-100 transition-colors text-sm font-medium shrink-0"
 title="Limpar todos os filtros"
 >
 <XCircle size={15} /> Limpar
 </button>
 )}
 <button onClick={() => fetchPlanejamento(false)} className="flex-1 bg-[#32423D] text-white py-2.5 px-4 rounded-lg flex items-center justify-center gap-2 hover:bg-[#1f2926] transition-colors shadow-md font-medium text-sm">
 <Search className="w-4 h-4" /> Buscar Planos
 </button>
 </div>
 </div>

 {fallbackMsg && (
 <div className="bg-amber-50 text-amber-800 px-3 py-1.5 rounded-lg border border-amber-200 text-sm font-medium animate-in fade-in slide-in-from-top-4 mt-4">
 {fallbackMsg}
 </div>
 )}
 {error && <div className="p-2 bg-red-50 text-red-600 rounded-md text-xs font-medium border border-red-100 mt-2">{error}</div>}

 {/* Totais KPI Cards */}
 <div className="grid grid-cols-1 md:grid-cols-3 gap-2 mt-2">
 <div className="bg-white rounded-md p-2 shadow-sm border border-gray-100 flex items-center gap-2 relative overflow-hidden">
 <div className="w-1 h-full bg-gray-200 absolute left-0 top-0" />
 <div className="p-1.5 bg-gray-50 rounded">
 <Target className="w-4 h-4 text-gray-400" />
 </div>
 <div>
 <p className="text-[9px] font-bold text-gray-400 uppercase tracking-wider">A Executar</p>
 <p className="text-lg font-black text-[#32423D] leading-none mt-0.5">{totalExecutar}</p>
 </div>
 </div>
 
 <div className="bg-white rounded-md p-2 shadow-sm border border-gray-100 flex items-center gap-2 relative overflow-hidden">
 <div className="w-1 h-full bg-[#E0E800] absolute left-0 top-0" />
 <div className="p-1.5 bg-[#E0E800]/10 rounded">
 <CheckCircle2 className="w-4 h-4 text-[#8a8f00]" />
 </div>
 <div>
