 const handleCancelarLiberacao = async (id: number) => {
 if (!confirm('Deseja realmente CANCELAR a libera├º├úo deste projeto?')) return;
 try {
 const res = await fetch(`${API_BASE}/projeto/${id}/cancelar-liberacao`, {
 method: 'POST',
