 </motion.button>
</div>
 </form>
 </motion.div>
 </motion.div>
 )
 }
 </AnimatePresence >
 </div >
 );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
 Search, RefreshCw, CheckCircle, FileCheck,
 ArrowLeft, ArrowLeftCircle, AlertTriangle, FileText,
 Loader2, Truck, History, RotateCcw, X
} from 'lucide-react';
import { useAlert } from '../contexts/AlertContext';
import { useAuth } from '../contexts/AuthContext';
import { formatToBRDate } from '../utils/dateUtils';

const API_BASE = '/api/romaneio-retorno';

// ÔöÇÔöÇÔöÇ Sub-view: Hist├│rico romaneioitemcontrole ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function HistoricoControleView({ item, onBack }: { item: Record<string, unknown>; onBack: () => void }) {
 const { showAlert } = useAlert();
 const { user } = useAuth();
 const [controles, setControles] = useState<Record<string, unknown>[]>([]);
 const [loading, setLoading] = useState(true);
 const [processingId, setProcessingId] = useState<number | null>(null);
 const [estornoModal, setEstornoModal] = useState<{ ctrl: Record<string, unknown>; obs: string; qtde: string } | null>(null);
 const [dateFilter, setDateFilter] = useState({ inicio: '', fim: '' });

 const fetchControles = async () => {
 setLoading(true);
 try {
 const res = await fetch(`${API_BASE}/controle/${item.IdOrdemServicoItem || item.IDOrdemServicoITEM}`);
 const data = await res.json();
 if (data.success) setControles(data.data);
 else showAlert(data.message, 'error');
 } catch {
 showAlert('Erro ao buscar hist├│rico de controle.', 'error');
 } finally {
 setLoading(false);
 }
 };

 useEffect(() => { fetchControles(); }, []);

 const handleEstorno = async () => {
 if (!estornoModal) return;
 const { ctrl, obs, qtde } = estornoModal;
 const ctrlId = ctrl.idromaneioitem ?? ctrl.IdRomaneioItem ?? null;
 if (!ctrlId) {
 showAlert('ID do registro de controle n├úo identificado. Atualize a lista e tente novamente.', 'error');
 setEstornoModal(null);
 return;
 }
 const maxQtde = Number(ctrl.qtdeUsuario ?? ctrl.QtdeUsuario ?? 0);
 const qtdeNum = Number(qtde);
 if (!qtdeNum || qtdeNum <= 0) {
 showAlert('Informe uma quantidade v├ílida para estorno.', 'warning');
 return;
 }
 if (qtdeNum > maxQtde) {
 showAlert(`Quantidade (${qtdeNum}) n├úo pode ser maior que a registrada (${maxQtde}).`, 'warning');
 return;
 }
 setProcessingId(ctrlId);
 setEstornoModal(null);
 try {
 const res = await fetch(`${API_BASE}/estorno/${ctrlId}`, {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({ usuario: user?.nome || 'Sistema', observacao: obs, qtdeEstorno: qtdeNum })
 });
 const data = await res.json();
 if (data.success) fetchControles();
 else showAlert(data.message, 'error');
 } catch {
 showAlert('Erro ao realizar estorno.', 'error');
 } finally {
 setProcessingId(null);
 }
 };

 const situacaoBadge = (s: string) => {
 if (!s) return 'bg-gray-100 text-gray-600';
 if (s === 'ESTORNO') return 'bg-red-100 text-red-700';
 if (s.includes('RETORNO') || s.includes('ENTRADA')) return 'bg-green-100 text-green-700';
 return 'bg-blue-100 text-blue-700';
 };

 return (
 <div className="flex-1 flex flex-col min-h-0 bg-gray-50">
 {/* Cabe├ºalho da sub-view */}
 <header className="bg-white border-b border-gray-200 px-3 py-1.5 shadow-sm flex items-center gap-3">
 <button
 onClick={onBack}
 className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-[#32423D] text-white text-sm font-medium hover:bg-[#26312D] transition-colors"
 >
 <ArrowLeft size={16} />
 Voltar
 </button>
 <div className="h-5 w-px bg-gray-300" />
 <div>
 <h2 className="text-sm font-bold text-gray-800 flex items-center gap-2">
 <History size={16} className="text-[#32423D]" />
 Hist├│rico de Controle ÔÇö{' '}
 <span className="text-[#32423D]">
 {item.DescResumo || item.CodMatFabricante || `ID: ${item.IdOrdemServicoItem || item.IDOrdemServicoITEM}`}
 </span>
 </h2>
 <p className="text-xs text-gray-500 mt-0.5">
 Projeto: <strong>{item.PROJETO}</strong> &nbsp;|&nbsp; Tag: <strong>{item.TAG}</strong> &nbsp;|&nbsp; Romaneio: <strong>#{item.IdRomaneio}</strong>
 </p>
 </div>
 <button
 onClick={fetchControles}
 className="ml-auto p-1.5 rounded-lg bg-gray-100 hover:bg-gray-200 transition-colors"
 title="Recarregar"
 >
 <RefreshCw size={15} className={loading ? 'animate-spin text-[#32423D]' : 'text-gray-500'} />
 </button>
 </header>

 {/* Tabela romaneioitemcontrole */}
 <main className="flex-1 overflow-auto p-4">
 <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
 {/* Filtro por data de retorno */}
 <div className="bg-gray-50 px-4 py-2 border-b border-gray-200 flex items-center gap-3 flex-wrap">
 <span className="text-xs font-bold text-gray-500 uppercase tracking-wide">Data Retorno:</span>
 <div className="flex items-center gap-1.5">
 <label className="text-[10px] text-gray-400 font-semibold uppercase">De</label>
 <input type="date" value={dateFilter.inicio} onChange={e => setDateFilter(f => ({ ...f, inicio: e.target.value }))}
 className="px-2 py-0.5 text-xs border border-gray-300 rounded focus:ring-1 focus:ring-[#32423D]/30 outline-none" />
 </div>
 <div className="flex items-center gap-1.5">
 <label className="text-[10px] text-gray-400 font-semibold uppercase">At├®</label>
 <input type="date" value={dateFilter.fim} onChange={e => setDateFilter(f => ({ ...f, fim: e.target.value }))}
 className="px-2 py-0.5 text-xs border border-gray-300 rounded focus:ring-1 focus:ring-[#32423D]/30 outline-none" />
 </div>
 {(dateFilter.inicio || dateFilter.fim) && (
 <button onClick={() => setDateFilter({ inicio: '', fim: '' })} className="text-[10px] text-red-500 hover:text-red-700 font-semibold flex items-center gap-0.5">
 <X size={11} /> Limpar
 </button>
 )}
 <span className="ml-auto text-xs text-gray-400 font-mono">{controles.filter(ctrl => {
 if (!dateFilter.inicio && !dateFilter.fim) return true;
 const d = ctrl.DataRetorno ? new Date(ctrl.DataRetorno) : null;
 if (!d) return false;
 if (dateFilter.inicio && d < new Date(dateFilter.inicio)) return false;
 if (dateFilter.fim) { const fim = new Date(dateFilter.fim); fim.setHours(23,59,59); if (d > fim) return false; }
 return true;
 }).length} registro(s)</span>
 </div>
 <div className="overflow-auto">
 <table className="w-full text-left border-collapse">
 <thead className="bg-[#567469] text-white text-[11px] uppercase sticky top-0 z-10">
 <tr>
 <th className="px-3 py-2 text-center">Qtde Usu├írio</th>
 <th className="px-3 py-2">Situa├º├úo</th>
 <th className="px-3 py-2">Data Retorno</th>
 <th className="px-3 py-2">Usu├írio Retorno</th>
 <th className="px-3 py-2">Observa├º├úo</th>
 <th className="px-3 py-2 text-center">Estorno</th>
 </tr>
 </thead>
 <tbody className="divide-y divide-gray-100 text-sm">
 {loading ? (
 <tr>
 <td colSpan={6} className="px-4 py-10 text-center">
 <Loader2 size={22} className="animate-spin text-[#32423D] mx-auto" />
 </td>
 </tr>
 ) : (() => {
 const filtered = controles.filter(ctrl => {
 if (!dateFilter.inicio && !dateFilter.fim) return true;
 const d = ctrl.DataRetorno ? new Date(ctrl.DataRetorno) : null;
 if (!d) return false;
 if (dateFilter.inicio && d < new Date(dateFilter.inicio)) return false;
 if (dateFilter.fim) { const fim = new Date(dateFilter.fim); fim.setHours(23,59,59); if (d > fim) return false; }
 return true;
 });
 return filtered.length === 0 ? (
 <tr>
 <td colSpan={6} className="px-4 py-10 text-center text-gray-400 italic text-sm">
 {controles.length === 0 ? 'Nenhum registro encontrado para este ID de OS Item.' : 'Nenhum registro no per├¡odo selecionado.'}
 </td>
 </tr>
 ) : filtered.map((ctrl) => (
 <tr key={ctrl.idromaneioitem ?? ctrl.IdRomaneioItem} className={`hover:bg-gray-50 transition-colors ${ctrl.Situacao === 'ESTORNO' ? 'opacity-60' : ''}`}>
 <td className="px-3 py-1.5 text-center font-bold text-blue-700">{ctrl.qtdeUsuario ?? ctrl.QtdeUsuario ?? '-'}</td>
 <td className="px-3 py-1.5">
 <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${situacaoBadge(ctrl.Situacao)}`}>
 {ctrl.Situacao || 'AGUARDANDO'}
 </span>
 </td>
 <td className="px-3 py-1.5 text-xs font-mono text-gray-500">{ctrl.DataRetorno ? formatToBRDate(ctrl.DataRetorno) : '-'}</td>
 <td className="px-3 py-1.5 text-xs font-medium text-[#32423D]">{ctrl.UsuarioRetorno || ctrl.Usuario || '-'}</td>
 <td className="px-3 py-1.5 text-xs text-gray-500 max-w-[200px] truncate" title={ctrl.Observacao}>{ctrl.Observacao || '-'}</td>
 <td className="px-3 py-1.5 text-center">
 {ctrl.Situacao === 'ESTORNO' ? (
 <span className="text-[10px] text-red-400 font-bold">ESTORNADO</span>
 ) : (
 <button
 onClick={() => setEstornoModal({ ctrl, obs: '', qtde: String(ctrl.qtdeUsuario ?? ctrl.QtdeUsuario ?? '') })}
 disabled={processingId === (ctrl.idromaneioitem ?? ctrl.IdRomaneioItem)}
 className="flex items-center gap-1 px-2 py-1 rounded-md bg-orange-50 text-orange-700 text-[11px] font-semibold border border-orange-200 hover:bg-orange-100 transition-colors disabled:opacity-50 mx-auto"
 title="Realizar Estorno: devolve qtde ao item do romaneio"
 >
 {processingId === (ctrl.idromaneioitem ?? ctrl.IdRomaneioItem)
 ? <Loader2 size={12} className="animate-spin" />
 : <RotateCcw size={12} />}
 Estornar
 </button>
 )}
 </td>
 </tr>
 ))})()}
 </tbody>
 </table>
 </div>
 </div>
 </main>

 {/* Modal Estorno com Observa├º├úo */}
 {estornoModal && (() => {
 const maxQtde = Number(estornoModal.ctrl.qtdeUsuario ?? estornoModal.ctrl.QtdeUsuario ?? 0);
 const qtdeNum = Number(estornoModal.qtde);
 const qtdeInvalida = qtdeNum > maxQtde;
 return (
 <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40" onClick={() => setEstornoModal(null)}>
 <div className="bg-white rounded-md shadow-2xl border border-gray-200 p-6 w-[420px]" onClick={e => e.stopPropagation()}>
 <h3 className="text-sm font-bold text-orange-700 mb-3 flex items-center gap-2">
 <RotateCcw size={15} /> Confirmar Estorno
 </h3>
 <div className="bg-orange-50 rounded-lg p-3 mb-4 text-xs">
 <p>Qtde registrada no retorno: <strong className="text-orange-700">{maxQtde}</strong></p>
 <p className="text-gray-500 mt-1">A quantidade digitada ser├í devolvida ao item do romaneio.</p>
 </div>
 <label className="block text-[11px] font-semibold text-gray-600 uppercase mb-1">Quantidade a estornar <span className="text-red-500">*</span></label>
 <input
 type="number" min={1} max={maxQtde}
 value={estornoModal.qtde}
 onChange={e => setEstornoModal({ ...estornoModal, qtde: e.target.value })}
 autoFocus
 placeholder={`M├íx: ${maxQtde}`}
 className={`w-full px-3 py-2 border rounded-lg text-sm outline-none mb-1 transition-colors ${
 qtdeInvalida
 ? 'border-red-400 bg-red-50 focus:ring-2 focus:ring-red-300'
 : 'border-gray-300 focus:ring-2 focus:ring-orange-400/40'
 }`}
 />
 {qtdeInvalida && (
 <p className="text-red-600 text-[11px] mb-3">Quantidade n├úo pode ser maior que {maxQtde}.</p>
 )}
 {!qtdeInvalida && <div className="mb-3" />}
 <label className="block text-[11px] font-semibold text-gray-600 uppercase mb-1">Observa├º├úo (opcional)</label>
 <input
 type="text" maxLength={150}
 value={estornoModal.obs}
 onChange={e => setEstornoModal({ ...estornoModal, obs: e.target.value })}
 onKeyDown={e => e.key === 'Enter' && handleEstorno()}
 placeholder="Motivo do estorno..."
 className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-orange-400/40 outline-none mb-4"
 />
 <div className="flex gap-2">
 <button
 onClick={handleEstorno}
 disabled={qtdeInvalida || !estornoModal.qtde}
 className="flex-1 bg-orange-600 text-white py-2 rounded-lg text-sm font-semibold hover:bg-orange-700 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
 >
 Confirmar Estorno
 </button>
 <button onClick={() => setEstornoModal(null)} className="px-4 py-2 rounded-lg border border-gray-300 text-sm text-gray-600 hover:bg-gray-50 transition-colors">
 Cancelar
 </button>
 </div>
 </div>
 </div>
 );
 })()}
 </div>
 );
}

// ÔöÇÔöÇÔöÇ P├ígina Principal: Romaneio-Retorno ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export default function RomaneioRetornoPage() {
 const { showAlert: addAlert } = useAlert();
 const { user } = useAuth();
 const [loading, setLoading] = useState(false);
 const [items, setItems] = useState<Record<string, unknown>[]>([]);
 const [selectedItem, setSelectedItem] = useState<Record<string, unknown> | null>(null);
 const [historicoItem, setHistoricoItem] = useState<Record<string, unknown> | null>(null); // Item para abrir sub-view
 const [filters, setFilters] = useState({
 romaneio: '',
 projeto: '',
 tag: '',
 numDoc: '',
 mostrarConcluidos: false
 });
 const [contextMenu, setContextMenu] = useState<{ x: number, y: number, type: 'item', data: Record<string, unknown> } | null>(null);
 const [retornoPanel, setRetornoPanel] = useState<{ item: Record<string, unknown> } | null>(null);
 const [retornoQtde, setRetornoQtde] = useState('');
 const [retornoSaving, setRetornoSaving] = useState(false);

 const fetchItems = async () => {
 setLoading(true);
 try {
 const query = new URLSearchParams(filters as Record<string, unknown>).toString();
 const res = await fetch(`${API_BASE}/items?${query}`);
 const data = await res.json();
 if (data.success) {
 setItems(data.data);
 setSelectedItem(null);
 }
 } catch {
 addAlert('Erro ao buscar itens', 'error');
 } finally {
 setLoading(false);
 }
 };

 const handleRegistrarRetorno = async () => {
 if (!retornoPanel) return;
 const qtde = Number(retornoQtde);
 const maxQ = Number(retornoPanel.item.QtdeEnviada) || 0;
 if (!qtde || qtde <= 0) { addAlert('Informe uma quantidade v├ílida.', 'warning'); return; }
 if (qtde > maxQ) { addAlert(`Quantidade (${qtde}) n├úo pode ser maior que a enviada (${maxQ}).`, 'warning'); return; }
 setRetornoSaving(true);
 try {
 const res = await fetch(`${API_BASE}/registrar-retorno`, {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({
 idRomaneioItem: retornoPanel.item.IdRomaneioItem,
 idRomaneio: retornoPanel.item.IdRomaneio,
 qtdeGrid: qtde,
 usuario: user?.nome || 'Sistema',
 nomeCompleto: user?.nome || 'Sistema'
 })
 });
 const data = await res.json();
 if (data.success) {
 setRetornoPanel(null); setRetornoQtde('');
 fetchItems();
 } else { addAlert(data.message, 'error'); }
 } catch { addAlert('Erro de conex├úo.', 'error'); }
 finally { setRetornoSaving(false); }
 };

 const handleProcessReturn = async (itemId: number, qtde: number, observacao: string, tipo: string) => {
 try {
 const res = await fetch(`${API_BASE}/process`, {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({ idRomaneioItem: itemId, qtdeRetorno: qtde, observacao, tipoRetorno: tipo, usuario: 'Sistema' })
 });
 const data = await res.json();
 if (data.success) { addAlert(data.message, 'success'); fetchItems(); }
 else addAlert(data.message, 'error');
 } catch { addAlert('Erro ao processar retorno', 'error'); }
 };

 const handleContextMenu = (e: React.MouseEvent, data: Record<string, unknown>) => {
 e.preventDefault();
 setContextMenu({ x: e.clientX, y: e.clientY, type: 'item', data });
 };

 useEffect(() => {
 const handleClick = () => setContextMenu(null);
 window.addEventListener('click', handleClick);
 return () => window.removeEventListener('click', handleClick);
 }, []);

 // Se estiver na sub-view de hist├│rico, renderiza ela
 if (historicoItem) {
 return <HistoricoControleView item={historicoItem} onBack={() => setHistoricoItem(null)} />;
 }

 return (
 <div className="flex flex-col flex-1 min-h-0 bg-gray-50 overflow-hidden">
 {/* ÔöÇÔöÇ PARTE 1: Filtros compactos ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
 <header className="bg-white border-b border-gray-200 px-4 py-2 shadow-sm">
 <div className="flex flex-wrap gap-2 items-end">
 <div className="flex-1 min-w-[110px]">
 <label className="block text-[10px] font-semibold text-gray-500 uppercase mb-0.5">Romaneio</label>
 <input
 type="text"
 value={filters.romaneio}
 onChange={e => setFilters({ ...filters, romaneio: e.target.value })}
 onKeyDown={e => e.key === 'Enter' && fetchItems()}
 className="w-full px-2 py-1 text-sm border border-gray-300 rounded focus:ring-2 focus:ring-[#32423D]/30 outline-none"
 placeholder="Ex: 15"
 />
 </div>
 <div className="flex-1 min-w-[110px]">
 <label className="block text-[10px] font-semibold text-gray-500 uppercase mb-0.5">Projeto</label>
 <input
 type="text"
 value={filters.projeto}
 onChange={e => setFilters({ ...filters, projeto: e.target.value })}
 onKeyDown={e => e.key === 'Enter' && fetchItems()}
 className="w-full px-2 py-1 text-sm border border-gray-300 rounded focus:ring-2 focus:ring-[#32423D]/30 outline-none"
 />
 </div>
 <div className="flex-1 min-w-[110px]">
 <label className="block text-[10px] font-semibold text-gray-500 uppercase mb-0.5">Tag</label>
 <input
 type="text"
 value={filters.tag}
 onChange={e => setFilters({ ...filters, tag: e.target.value })}
 onKeyDown={e => e.key === 'Enter' && fetchItems()}
 className="w-full px-2 py-1 text-sm border border-gray-300 rounded focus:ring-2 focus:ring-[#32423D]/30 outline-none"
 />
 </div>
 <div className="flex-1 min-w-[110px]">
 <label className="block text-[10px] font-semibold text-gray-500 uppercase mb-0.5">C├│d. Material</label>
 <input
 type="text"
 value={filters.numDoc}
 onChange={e => setFilters({ ...filters, numDoc: e.target.value })}
 onKeyDown={e => e.key === 'Enter' && fetchItems()}
 className="w-full px-2 py-1 text-sm border border-gray-300 rounded focus:ring-2 focus:ring-[#32423D]/30 outline-none"
 />
 </div>
 <div className="flex items-center gap-1.5 pb-0.5">
 <input
 type="checkbox"
 checked={filters.mostrarConcluidos}
 onChange={e => setFilters({ ...filters, mostrarConcluidos: e.target.checked })}
 id="mostrarConcluidos"
 className="w-3.5 h-3.5 text-[#32423D] border-gray-300 rounded"
 />
 <label htmlFor="mostrarConcluidos" className="text-xs text-gray-600 whitespace-nowrap">Mostrar Conclu├¡dos</label>
 </div>
 <button
 onClick={fetchItems}
 disabled={loading}
 className="flex items-center gap-1.5 bg-[#32423D] text-white px-4 py-1.5 rounded hover:bg-[#26312D] transition-colors disabled:opacity-50 text-sm font-medium"
 >
 {loading ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Search className="w-3.5 h-3.5" />}
 Pesquisar
 </button>
 </div>
 </header>

 {/* ÔöÇÔöÇ PARTE 2: Grid de Itens ÔÇö denso + coluna IdOrdemServicoItem ÔöÇÔöÇ */}
 <main className="flex-1 overflow-hidden p-3 flex flex-col">
 <section className="flex-1 bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden flex flex-col">
 <div className="bg-gray-50 px-3 py-1.5 border-b border-gray-200 flex justify-between items-center">
 <h2 className="text-xs font-bold text-gray-700 flex items-center gap-2">
 <Truck className="w-3.5 h-3.5 text-[#32423D]" />
 ITENS DO ROMANEIO PARA RETORNO
 </h2>
 <div className="flex items-center gap-3">
 {selectedItem && (
 <span className="text-[11px] text-[#32423D] font-semibold animate-pulse">
 Item #{selectedItem.IdRomaneioItem} selecionado
 </span>
 )}
 <span className="text-[11px] text-gray-400 font-mono">{items.length} itens</span>
 </div>
 </div>
 <div className="flex-1 overflow-auto">
 <table className="w-full text-left border-collapse">
 <thead className="bg-[#567469] text-white text-[11px] uppercase sticky top-0 z-10">
 <tr>
 <th className="px-3 py-1.5">Status</th>
 <th className="px-3 py-1.5">Romaneio</th>
 <th className="px-3 py-1.5">ID OS Item</th>
 <th className="px-3 py-1.5">Projeto</th>
 <th className="px-3 py-1.5">Tag</th>
 <th className="px-3 py-1.5 text-right">Qtde Env.</th>
 <th className="px-3 py-1.5 text-right">Qtde Ret.</th>
 <th className="px-3 py-1.5 text-right">Saldo</th>
 <th className="px-3 py-1.5">Situa├º├úo</th>
 <th className="px-3 py-1.5 text-center">Hist├│rico</th>
 </tr>
 </thead>
 <tbody className="divide-y divide-gray-100 text-[12px]">
 {items.length === 0 ? (
 <tr>
 <td colSpan={10} className="px-4 py-10 text-center text-gray-400 italic text-sm">
 {loading
 ? <Loader2 size={20} className="animate-spin text-[#32423D] mx-auto" />
 : 'Nenhum item encontrado. Use os filtros acima para pesquisar.'}
 </td>
 </tr>
 ) : items.map((item) => (
 <tr
 key={item.IdRomaneioItem}
 onClick={() => setSelectedItem(selectedItem?.IdRomaneioItem === item.IdRomaneioItem ? null : item)}
 onContextMenu={(e) => handleContextMenu(e, item)}
 className={`hover:bg-[#E0E800]/10 cursor-pointer transition-colors border-l-4 ${selectedItem?.IdRomaneioItem === item.IdRomaneioItem
 ? 'bg-[#E0E800]/15 border-[#32423D]'
 : 'border-transparent'}`}
 >
 <td className="px-3 py-1">
 {item.MarcarComoFinalizado === 'S'
 ? <CheckCircle className="w-3.5 h-3.5 text-green-500" />
 : <RefreshCw className="w-3.5 h-3.5 text-blue-400" />}
 </td>
 <td className="px-3 py-1 font-mono text-gray-500">#{item.IdRomaneio}</td>
 <td className="px-3 py-1 font-mono font-bold text-[#32423D]">{item.IdOrdemServicoItem || item.IDOrdemServicoITEM || '-'}</td>
 <td className="px-3 py-1 text-gray-700 max-w-[180px] truncate" title={item.PROJETO}>{item.PROJETO}</td>
 <td className="px-3 py-1 font-semibold text-blue-900">{item.TAG}</td>
 <td className="px-3 py-1 text-right font-bold">{item.QtdeEnviada}</td>
 <td className="px-3 py-1 text-right text-green-600 font-bold">{item.QtdeTotalRetorno || 0}</td>
 <td className="px-3 py-1 text-right text-red-600 font-bold">{item.Saldo}</td>
 <td className="px-3 py-1">
 <span className={`px-1.5 py-0.5 rounded-full text-[10px] uppercase font-bold ${item.Situacao?.includes('RETORNO') ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'}`}>
 {item.Situacao || 'AGUARDANDO'}
 </span>
 </td>
 <td className="px-3 py-1 text-center" onClick={e => e.stopPropagation()}>
 <div className="flex items-center gap-1 justify-center flex-wrap">
 {selectedItem?.IdRomaneioItem === item.IdRomaneioItem && (() => {
 const saldo = Number(item.Saldo) || 0;
 return saldo > 0 ? (
 <button
 onClick={() => { setRetornoPanel({ item }); setRetornoQtde(''); }}
 className="flex items-center gap-1 px-2 py-0.5 rounded bg-green-50 text-green-700 text-[10px] font-bold border border-green-300 hover:bg-green-100 transition-colors"
 title={`Totalizar retorno de pe├ºas (saldo: ${saldo})`}
 >
 Ôå® Retorno
 </button>
 ) : (
 <span
 className="flex items-center gap-1 px-2 py-0.5 rounded bg-gray-100 text-gray-400 text-[10px] font-bold border border-gray-200 cursor-not-allowed"
 title="Saldo zerado ÔÇö sem pe├ºas para retornar"
 >
 Ôå® Retorno
 </span>
 );
 })()}
 <button
 onClick={() => setHistoricoItem(item)}
 className="flex items-center gap-1 px-2 py-0.5 rounded bg-indigo-50 text-indigo-700 text-[10px] font-semibold border border-indigo-200 hover:bg-indigo-100 transition-colors"
 title="Abrir hist├│rico de controle (romaneioitemcontrole)"
 >
 <History size={11} />
 Ver Hist.
 </button>
 </div>
 </td>
 </tr>
 ))}
 </tbody>
 </table>
 </div>
 </section>
 </main>

 {/* Painel Inline ÔÇö Totalizar Retorno */}
 {retornoPanel && (
 <div className="fixed inset-0 z-40 flex items-center justify-center bg-black/40" onClick={() => { setRetornoPanel(null); setRetornoQtde(''); }}>
 <div className="bg-white rounded-md shadow-2xl border border-gray-200 p-6 w-[400px]" onClick={e => e.stopPropagation()}>
 <div className="flex items-center justify-between mb-4">
 <h3 className="text-sm font-bold text-[#32423D] flex items-center gap-2">
 <span>Ôå®</span> Totalizar Retorno
 </h3>
 <button onClick={() => { setRetornoPanel(null); setRetornoQtde(''); }} className="text-gray-400 hover:text-gray-600">Ô£ò</button>
 </div>
 <div className="bg-gray-50 rounded-lg p-3 mb-4 text-xs space-y-1">
 <div className="flex justify-between"><span className="text-gray-500">Romaneio:</span><strong>#{retornoPanel.item.IdRomaneio}</strong></div>
 <div className="flex justify-between"><span className="text-gray-500">Projeto / Tag:</span><strong>{retornoPanel.item.PROJETO} / {retornoPanel.item.TAG}</strong></div>
 <div className="flex justify-between"><span className="text-gray-500">Qtde Enviada:</span><strong className="text-blue-700">{retornoPanel.item.QtdeEnviada}</strong></div>
 <div className="flex justify-between"><span className="text-gray-500">J├í retornado:</span><strong className="text-green-700">{retornoPanel.item.QtdeTotalRetorno || 0}</strong></div>
 </div>
 <label className="block text-[11px] font-semibold text-gray-600 uppercase mb-1">Quantidade que retornou</label>
 <input
 type="number" min={1} max={Number(retornoPanel.item.QtdeEnviada)}
 value={retornoQtde}
 onChange={e => setRetornoQtde(e.target.value)}
 onKeyDown={e => e.key === 'Enter' && handleRegistrarRetorno()}
 autoFocus
 placeholder={'Max: ' + retornoPanel.item.QtdeEnviada}
 className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-[#32423D]/40 outline-none mb-4"
 />
 <div className="flex gap-2">
 <button
 onClick={handleRegistrarRetorno}
 disabled={retornoSaving}
 className="flex-1 bg-[#32423D] text-white py-2 rounded-lg text-sm font-semibold hover:bg-[#26312D] disabled:opacity-50 transition-colors flex items-center justify-center gap-2"
 >
 {retornoSaving ? '...' : 'Ô£ô Confirmar Retorno'}
 </button>
 <button onClick={() => { setRetornoPanel(null); setRetornoQtde(''); }} className="px-4 py-2 rounded-lg border border-gray-300 text-sm text-gray-600 hover:bg-gray-50 transition-colors">
 Cancelar
 </button>
 </div>
 </div>
 </div>
 )}

 {/* Context Menu */}
 <AnimatePresence>
 {contextMenu && (
 <motion.div
 initial={{ opacity: 0, scale: 0.95 }}
 animate={{ opacity: 1, scale: 1 }}
 exit={{ opacity: 0, scale: 0.95 }}
 style={{ top: contextMenu.y, left: contextMenu.x }}
 className="fixed z-50 bg-white border border-gray-200 rounded-lg shadow-xl py-1 w-64 overflow-hidden"
 >
 <div className="px-3 py-1.5 bg-gray-50 border-b border-gray-100 text-[10px] font-bold text-gray-400 uppercase tracking-tighter">
 A├º├Áes ÔÇö Item #{contextMenu.data?.IdRomaneioItem}
 </div>
 {(() => {
 const d = contextMenu.data;
 const saldo = Number(d.Saldo) || 0;
 return saldo > 0 ? (
 <button
 onClick={() => { setRetornoPanel({ item: d }); setRetornoQtde(''); setContextMenu(null); }}
 className="w-full flex items-center gap-3 px-4 py-2 hover:bg-green-50 text-sm text-green-700 group transition-colors font-semibold"
 >
 <span className="w-4 h-4 text-center">Ôå®</span>
 <span>Totalizar Retorno</span>
 </button>
 ) : (
 <div className="w-full flex items-center gap-3 px-4 py-2 text-sm text-gray-400 cursor-not-allowed" title="Saldo zerado">
 <span className="w-4 h-4 text-center">Ôå®</span>
 <span>Totalizar Retorno (sem saldo)</span>
 </div>
 );
 })()}
 <div className="border-t border-gray-100 my-1" />
 <button
 onClick={() => { setHistoricoItem(contextMenu.data); setContextMenu(null); }}
 className="w-full flex items-center gap-3 px-4 py-2 hover:bg-indigo-50 text-sm text-indigo-700 group transition-colors"
 >
 <History className="w-4 h-4" />
 <span>Ver Hist├│rico de Controle</span>
 </button>
 <div className="border-t border-gray-100 my-1" />
 <button
 onClick={() => {
 const d = contextMenu.data;
 handleProcessReturn(d.IdRomaneioItem, Number(d.Saldo) || 0, 'Entrada em lote', 'ENTRADA/RETORNO');
 setContextMenu(null);
 }}
 className="w-full flex items-center gap-3 px-4 py-2 hover:bg-[#E0E800]/10 text-sm text-gray-700 group transition-colors"
 >
 <FileCheck className="w-4 h-4 text-amber-500" />
 <span>Marcar como Entrada/Retorno</span>
 </button>
 <button className="w-full flex items-center gap-3 px-4 py-2 hover:bg-[#E0E800]/10 text-sm text-gray-700 group transition-colors">
 <ArrowLeftCircle className="w-4 h-4 text-orange-600" />
 <span>Marcar como Item Finalizado</span>
 </button>
 <button className="w-full flex items-center gap-3 px-4 py-2 hover:bg-[#E0E800]/10 text-sm text-gray-700 group transition-colors">
 <AlertTriangle className="w-4 h-4 text-red-600" />
 <span>Gerar RNC - Pend├¬ncia Retorno</span>
 </button>
 <button className="w-full flex items-center gap-3 px-4 py-2 hover:bg-[#E0E800]/10 text-sm text-gray-700 group transition-colors">
 <FileText className="w-4 h-4 text-red-700" />
 <span>Abrir Desenho PDF</span>
 </button>
 </motion.div>
 )}
 </AnimatePresence>
 </div>
 );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Database, Save, AlertTriangle, ShieldCheck, RefreshCcw, Server, Users, Plus, GitCompare, ArrowRight, CheckCircle, Code, LogOut, XCircle, Search, X, Trash2, Monitor } from 'lucide-react';
import { useToast } from '../contexts/ToastContext';

interface SuperadminPageProps {
 defaultTab?: 'config' | 'tenants' | 'schema' | 'users';
}

export default function SuperadminPage({ defaultTab = 'users' }: SuperadminPageProps) {
 const { addToast } = useToast();
 const [isAuthenticated, setIsAuthenticated] = useState(false);
 const [loading, setLoading] = useState(false);
 const [activeTab, setActiveTab] = useState<'config' | 'tenants' | 'schema' | 'users' | 'audit'>(defaultTab);

 // Auth State
 const [username, setUsername] = useState('');
 const [password, setPassword] = useState('');

 // DB Config State (Single Tenant / Local Fallback)
 const [dbConfig, setDbConfig] = useState({
 host: '', user: '', password: '', database: '', port: 3306
 });

 // Tenant Management State
 const [tenants, setTenants] = useState<Record<string, unknown>[]>([]);
 const [newTenant, setNewTenant] = useState({
 nome_cliente: '', db_host: '', db_user: '', db_pass: '', db_name: '', db_port: 3306, copia_banco_dados: ''
 });

 // Schema Compare State
 const [sourceDbId, setSourceDbId] = useState<number | ''>('');
 const [destDbId, setDestDbId] = useState<number | ''>('');
 const [schemaActions, setSchemaActions] = useState<Record<string, unknown>[]>([]);
 const [comparing, setComparing] = useState(false);
 const [hasCompared, setHasCompared] = useState(false);
 const [selectedActions, setSelectedActions] = useState<Set<number>>(new Set());
 const [syncResults, setSyncResults] = useState<Record<string, unknown>[]>([]);
 const [syncing, setSyncing] = useState(false);
 const [showHistory, setShowHistory] = useState(false);
 const [history, setHistory] = useState<Record<string, unknown>[]>([]);

 // Tenant Search
 const [tenantSearch, setTenantSearch] = useState('');

 // Users State
 const [users, setUsers] = useState<Record<string, unknown>[]>([]);

 // Login Audit State
 const [auditLogs, setAuditLogs] = useState<Record<string, unknown>[]>([]);
 const [loadingAudit, setLoadingAudit] = useState(false);
 const [auditHoras, setAuditHoras] = useState(24);

 useEffect(() => {
 const sincoUserRaw = localStorage.getItem('sinco_user');
 const sincoToken = localStorage.getItem('sinco_token');

 if (sincoUserRaw && sincoToken) {
 try {
 const sincoUser = JSON.parse(sincoUserRaw);
 const hasSuperCreds =
 sincoUser.isSuperadmin === true ||
 sincoUser.superadmin === 'S' ||
 sincoUser.login?.toLowerCase() === 'superadmin';

 if (hasSuperCreds) {
 // Sempre sincronizar superadmin_token com o sinco_token atual
 localStorage.setItem('superadmin_token', sincoToken);
 setIsAuthenticated(true);
 fetchTenants(sincoToken);
 fetchUsers(sincoToken);
 return;
 }
 } catch {
 console.error('Erro ao verificar sess├úo principal', e);
 }
 }

 // Fallback: token de login manual do painel admin
 const superToken = localStorage.getItem('superadmin_token');
 if (superToken) {
 checkAuth(superToken);
 }
 }, []);

 const fetchAuditLogs = async (horas = auditHoras) => {
 const token = localStorage.getItem('superadmin_token');
 if (!token) return;
 setLoadingAudit(true);
 try {
 const res = await fetch(`/api/admin/login-audit?horas=${horas}`, {
 headers: { 'Authorization': `Bearer ${token}` }
 });
 const data = await res.json();
 if (data.success) setAuditLogs(data.data);
 } catch { addToast({ type: 'error', message: 'Erro ao buscar registros de acesso' }); }
 finally { setLoadingAudit(false); }
 };

 const handleCleanAudit = async () => {
 if (!confirm('Remover todos os registros com mais de 24 horas?')) return;
 const token = localStorage.getItem('superadmin_token');
 if (!token) return;
 try {
 const res = await fetch('/api/admin/login-audit', {
 method: 'DELETE',
 headers: { 'Authorization': `Bearer ${token}` }
 });
 const data = await res.json();
 if (data.success) {
 addToast({ type: 'success', message: data.message });
 fetchAuditLogs();
 }
 } catch { addToast({ type: 'error', message: 'Erro ao limpar registros' }); }
 };


 const checkAuth = async (token: string) => {
 try {
 const res = await fetch('/api/admin/check-auth', {
 headers: { 'Authorization': `Bearer ${token}` }
 });
 const data = await res.json();
 if (data.success) {
 setIsAuthenticated(true);
 fetchTenants(token);
 fetchUsers(token);
 } else {
 localStorage.removeItem('superadmin_token');
 setIsAuthenticated(false);
 }
 } catch {
 console.error(error);
 localStorage.removeItem('superadmin_token');
 setIsAuthenticated(false);
 }
 };

 const fetchTenants = async (token: string) => {
 try {
 const res = await fetch('/api/admin/databases', {
 headers: { 'Authorization': `Bearer ${token}` }
 });
 const data = await res.json();
 if (data.success) {
 setTenants(data.data);
 }
 } catch {
 console.error('Error fetching tenants:', error);
 }
 };

 const fetchUsers = async (token: string) => {
 try {
 const res = await fetch('/api/admin/users', {
 headers: { 'Authorization': `Bearer ${token}` }
 });
 const data = await res.json();
 if (data.success) setUsers(data.data);
 } catch {
 console.error(error);
 }
 };

 const handleToggleSuperadmin = async (userId: number, currentStatus: string) => {
 const newStatus = currentStatus === 'S' ? 'N' : 'S';
 try {
 const token = localStorage.getItem('superadmin_token');
 const res = await fetch(`/api/admin/users/${userId}`, {
 method: 'PUT',
 headers: {
 'Content-Type': 'application/json',
 'Authorization': `Bearer ${token}`
 },
 body: JSON.stringify({ superadmin: newStatus })
 });
 const data = await res.json();
 if (data.success) {
 addToast({ type: 'success', message: 'Status atualizado com sucesso' });
 if (token) fetchUsers(token);
 } else {
 addToast({ type: 'error', message: data.message });
 }
 } catch {
 addToast({ type: 'error', message: 'Erro ao atualizar usu├írio' });
 }
 };

 const handleLogin = async (e: React.FormEvent) => {
 e.preventDefault();

 // Client-side check removed to allow backend authentication
 console.log('Tentando login com:', username);

 setLoading(true);
 try {
 // Authenticate against Central DB (using the same credentials for verification against the DB record)
 const res = await fetch('/api/admin/login', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({ username, password })
 });
 const data = await res.json();

 if (data.success) {
 localStorage.setItem('superadmin_token', data.token);

 // Store Superadmin status in memory/storage as requested
 localStorage.setItem('superadmin_active_session', 'true');

 setIsAuthenticated(true);
 addToast({ type: 'success', message: 'Login realizado com sucesso' });
 fetchTenants(data.token);
 fetchUsers(data.token);
 } else {
 addToast({ type: 'error', message: data.message || 'Credenciais inv├ílidas no banco de dados' });
 }
 } catch {
 addToast({ type: 'error', message: 'Erro ao realizar login' });
 } finally {
 setLoading(false);
 }
 };

 // --- TENANT MANAGEMENT HANDLERS ---
 const handleAddTenant = async () => {
 const token = localStorage.getItem('superadmin_token');
 if (!token) return;
 setLoading(true);
 try {
 const res = await fetch('/api/admin/databases', {
 method: 'POST',
 headers: {
 'Content-Type': 'application/json',
 'Authorization': `Bearer ${token}`
 },
 body: JSON.stringify(newTenant)
 });
 const data = await res.json();
 if (data.success) {
 addToast({ type: 'success', message: 'Banco cadastrado com sucesso' });
 setNewTenant({ nome_cliente: '', db_host: '', db_user: '', db_pass: '', db_name: '', db_port: 3306, copia_banco_dados: '' });
 fetchTenants(token);
 } else {
 addToast({ type: 'error', message: data.message });
 }
 } catch {
 addToast({ type: 'error', message: 'Erro ao criar banco' });
 } finally {
 setLoading(false);
 }
 };

 const handleSyncUsers = async (dbId: number) => {
 const token = localStorage.getItem('superadmin_token');
 if (!token) return;
 setLoading(true);
 try {
 const res = await fetch(`/api/admin/sync-users/${dbId}`, {
 method: 'POST',
 headers: { 'Authorization': `Bearer ${token}` }
 });
 const data = await res.json();
 if (data.success) {
 addToast({ type: 'success', message: data.message });
 fetchUsers(token);
 } else {
 addToast({ type: 'error', message: data.message });
 }
 } catch {
 addToast({ type: 'error', message: 'Erro ao sincronizar usu├írios' });
 } finally {
 setLoading(false);
 }
 };

 const handleSyncAllUsers = async () => {
 const token = localStorage.getItem('superadmin_token');
 if (!token) return;
 if (!confirm('Deseja iniciar a sincroniza├º├úo global de todos os clientes? Isso pode levar alguns segundos.')) return;
 
 setLoading(true);
 try {
 const res = await fetch(`/api/admin/sync-all`, {
 method: 'POST',
 headers: { 'Authorization': `Bearer ${token}` }
 });
 const data = await res.json();
 if (data.success) {
 addToast({ type: 'success', message: data.message });
 fetchUsers(token);
 } else {
 addToast({ type: 'error', message: data.message });
 }
 } catch {
 addToast({ type: 'error', message: 'Erro ao sincronizar todos os usu├írios' });
 } finally {
 setLoading(false);
 }
 };

 // Access Tenant Handler
 const handleAccessTenant = async (tenant: Record<string, unknown>) => {
 if (!confirm(`Deseja acessar o sistema no ambiente: ${tenant.nome_cliente}?`)) return;

 // sinco_token tem isSuperadmin=true ÔÇö /api/superadmin/switch-db aceita diretamente
 const activeToken = localStorage.getItem('sinco_token') || localStorage.getItem('superadmin_token');
 if (!activeToken) {
 addToast({ type: 'error', message: 'Sess├úo n├úo encontrada. Fa├ºa login novamente.' });
 return;
 }

 setLoading(true);
 try {
 const res = await fetch('/api/superadmin/switch-db', {
 method: 'POST',
 headers: {
 'Content-Type': 'application/json',
 'Authorization': `Bearer ${activeToken}`
 },
 body: JSON.stringify({ dbName: tenant.db_name })
 });

 const data = await res.json();
 console.log('[SuperAdmin] switch-db response:', data.success, data.message || '');

 if (data.success && data.token) {
 const userData = {
 id: data.user?.id || 1,
 nome: data.user?.nome || 'Superadmin',
 login: data.user?.login || 'superadmin',
 role: 'admin',
 isSuperadmin: true,
 superadmin: 'S',
 clientName: tenant.nome_cliente,
 dbName: tenant.db_name,
 };

 // Preservar token original para retorno ao painel
 localStorage.setItem('superadmin_token', activeToken);
 localStorage.setItem('sinco_token', data.token);
 localStorage.setItem('sinco_user', JSON.stringify(userData));

 addToast({ type: 'success', message: `Conectando ao ambiente ${tenant.nome_cliente}...` });
 setTimeout(() => { window.location.href = '/dashboard'; }, 800);
 } else {
 addToast({ type: 'error', message: data.message || 'Erro ao trocar banco.' });
 }
 } catch {
 console.error('[SuperAdmin] Error switching tenant:', error);
 addToast({ type: 'error', message: 'Erro de conex├úo ao trocar banco.' });
 } finally {
 setLoading(false);
 }
 };


 // --- SCHEMA COMPARE HANDLERS ---
 const handleCompareSchema = async () => {
 const token = localStorage.getItem('superadmin_token');
 if (!token || !sourceDbId || !destDbId) return;

 setComparing(true);
 setHasCompared(false);
 setSchemaActions([]);

 try {
 const res = await fetch('/api/admin/schema/compare', {
 method: 'POST',
 headers: {
 'Content-Type': 'application/json',
 'Authorization': `Bearer ${token}`
 },
 body: JSON.stringify({ sourceDbId, destDbId })
 });
 const data = await res.json();
 if (data.success) {
 setSchemaActions(data.actions);
 setHasCompared(true);
 if (data.actions.length === 0) {
 addToast({ type: 'success', message: 'Estruturas id├¬nticas! Nenhuma a├º├úo necess├íria.' });
 }
 } else {
 addToast({ type: 'error', message: data.message });
 }
 } catch {
 addToast({ type: 'error', message: 'Erro ao comparar schemas' });
 } finally {
 setComparing(false);
 }
 };

 const handleSyncSchema = async (onlySelected = true) => {
 const token = localStorage.getItem('superadmin_token');
 if (!token || !destDbId) return;
 const toRun = onlySelected && selectedActions.size > 0
 ? schemaActions.filter((_: Record<string, unknown>, i: number) => selectedActions.has(i))
 : [...schemaActions];
 if (!toRun.length) { addToast({ type: 'error', message: 'Nenhuma diverg├¬ncia selecionada' }); return; }
 if (!confirm('Executar ' + toRun.length + ' altera├º├úo(├Áes)? Erros SQL ser├úo ignorados e listados.')) return;
 setSyncing(true); setSyncResults([]);
 try {
 const srcTenant = tenants.find((t: Record<string, unknown>) => t.id === sourceDbId);
 const res = await fetch('/api/admin/schema/sync', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
 body: JSON.stringify({ destDbId, actions: toRun, sourceDbName: srcTenant?.db_name || 'origem' })
 });
 const data = await res.json();
 if (data.success) {
 setSyncResults(data.results || []);
 const ok = (data.results || []).filter((r: Record<string, unknown>) => r.status === 'ok').length;
 const err = (data.results || []).filter((r: Record<string, unknown>) => r.status === 'erro').length;
 addToast({ type: err > 0 ? 'error' : 'success', message: ok + ' executado(s) ┬À ' + err + ' com erro(s)' });
 const runSet = new Set(toRun.map((a: Record<string, unknown>) => a.sql));
 setSchemaActions((prev: Record<string, unknown>[]) => prev.filter((a: Record<string, unknown>) => !runSet.has(a.sql)));
 setSelectedActions(new Set());
 } else { addToast({ type: 'error', message: data.message }); }
 } catch { addToast({ type: 'error', message: 'Erro ao sincronizar schema' }); }
 finally { setSyncing(false); }
 };

 const fetchHistory = async () => {
 const token = localStorage.getItem('superadmin_token');
 const dest = tenants.find((t: Record<string, unknown>) => t.id === destDbId);
 try {
 const res = await fetch('/api/admin/schema/history?banco=' + (dest?.db_name || '') + '&limit=100',
 { headers: { 'Authorization': 'Bearer ' + token } });
 const data = await res.json();
 if (data.success) { setHistory(data.data); setShowHistory(true); }
 } catch { addToast({ type: 'error', message: 'Erro ao buscar hist├│rico' }); }
 };

 const toggleSelectAll = () => {
 if (selectedActions.size === schemaActions.length) setSelectedActions(new Set());
 else setSelectedActions(new Set(schemaActions.map((_: Record<string, unknown>, i: number) => i)));
 };

 // --- DB CONFIG HANDLERS ---
 const handleTestConnection = async () => {
 const token = localStorage.getItem('superadmin_token');
 if (!token) return;
 setLoading(true);
 try {
 const res = await fetch('/api/admin/db/test', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
 body: JSON.stringify(dbConfig)
 });
 const data = await res.json();
 if (data.success) addToast({ type: 'success', message: data.message });
 else addToast({ type: 'error', message: data.message });
 } catch { addToast({ type: 'error', message: 'Erro ao testar conex├úo' }); } finally { setLoading(false); }
 };

 const handleSaveConfig = async () => {
 const token = localStorage.getItem('superadmin_token');
 if (!token) return;
 if (!confirm('Tem certeza? Isso ir├í alterar a conex├úo do banco de dados e aplicar as novas configura├º├Áes.')) return;
 setLoading(true);
 try {
 const res = await fetch('/api/admin/db/save', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
 body: JSON.stringify(dbConfig)
 });
 const data = await res.json();
 if (data.success) addToast({ type: 'success', message: data.message });
 else addToast({ type: 'error', message: data.message });
 } catch { addToast({ type: 'error', message: 'Erro ao salvar configura├º├úo' }); } finally { setLoading(false); }
 };

 if (!isAuthenticated) {
 return (
 <div className="flex items-center justify-center min-h-[60vh] h-full flex flex-col min-h-0">
 <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="w-full max-w-md p-8 bg-white rounded-md shadow-xl border border-gray-100">
 <div className="flex flex-col items-center mb-6">
 <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mb-4 text-red-600"><ShieldCheck size={32} /></div>
 
 <p className="text-gray-500 text-sm">├ürea restrita para gerenciamento do sistema</p>
 </div>
 <form onSubmit={handleLogin} className="space-y-4">
 <div><label className="block text-sm font-medium text-gray-700 mb-1">Usu├írio</label><input type="text" value={username} onChange={(e) => setUsername(e.target.value)} className="w-full px-4 py-2 border rounded-lg" /></div>
 <div><label className="block text-sm font-medium text-gray-700 mb-1">Senha</label><input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-4 py-2 border rounded-lg" /></div>
 <button type="submit" disabled={loading} className="w-full py-3 bg-red-600 text-white rounded-lg font-semibold flex justify-center items-center gap-2">{loading ? <RefreshCcw className="animate-spin" size={20} /> : 'Entrar no Painel'}</button>

 <button
 type="button"
 onClick={() => window.location.href = '/dashboard'}
 className="w-full py-3 mt-2 bg-gray-100 text-gray-700 rounded-lg font-semibold flex justify-center items-center gap-2 hover:bg-gray-200 transition-colors"
 >
 <ArrowRight className="rotate-180" size={20} /> Voltar para o Sistema
 </button>

 <button
 type="button"
 onClick={async () => {
 if (confirm('Deseja realmente fechar a aplica├º├úo e encerrar os servidores?')) {
 try {
 await fetch('/api/admin/shutdown', { method: 'POST' });
 } catch {
 console.error('Erro ao encerrar servidor:', e);
 }
 window.close();
 // Fallback if window.close() is blocked
 setTimeout(() => window.location.href = 'about:blank', 500);
 }
 }}
 className="w-full py-3 mt-2 border border-red-200 text-red-600 rounded-lg font-semibold flex justify-center items-center gap-2 hover:bg-red-50 transition-colors"
 >
 <XCircle size={20} /> Sair / Fechar App
 </button>
 </form>
 </motion.div>
 </div>
 );
 }

 return (
 <div className="space-y-4 w-full h-full overflow-y-auto max-w-[1920px] mx-auto pb-20 px-2 md:px-4">
 <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} className="bg-gradient-to-r from-gray-900 to-gray-800 rounded-md p-5 text-white shadow-xl relative overflow-hidden shrink-0 mt-2">
 <div className="absolute top-0 right-0 p-32 bg-white/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>
 <div className="relative z-10 flex justify-between items-center">
 <div>
 
 <p className="text-gray-400 mt-2">Gerenciamento Multi-Tenant e Configura├º├Áes</p>
 </div>
 <button
 onClick={() => {
 if (confirm('Deseja sair do Painel Superadmin?')) {
 setIsAuthenticated(false);
 localStorage.removeItem('superadmin_token');
 localStorage.removeItem('superadmin_active_session');
 window.location.href = '/';
 }
 }}
 className="px-4 py-2 bg-red-600/20 hover:bg-red-600/30 text-red-400 rounded-lg flex items-center gap-2 transition-colors border border-red-600/30"
 >
 <LogOut size={18} /> Sair do Painel
 </button>
 </div>
 </motion.div>

 {/* Tabs */}
 <div className="flex space-x-1 bg-gray-100 p-1 rounded-md overflow-x-auto">
 <button onClick={() => setActiveTab('tenants')} className={`flex-1 min-w-[150px] py-2.5 text-sm font-medium rounded-lg transition-all ${activeTab === 'tenants' ? 'bg-white text-[#32423D] shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
 <div className="flex items-center justify-center gap-2"><Server size={16} /> Gest├úo de Bancos</div>
 </button>
 <button onClick={() => setActiveTab('users')} className={`flex-1 min-w-[150px] py-2.5 text-sm font-medium rounded-lg transition-all ${activeTab === 'users' ? 'bg-white text-[#32423D] shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
 <div className="flex items-center justify-center gap-2"><Users size={16} /> Usu├írios Globais</div>
 </button>
 <button onClick={() => setActiveTab('schema')} className={`flex-1 py-2.5 text-sm font-medium rounded-lg transition-all ${activeTab === 'schema' ? 'bg-white text-purple-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
 <div className="flex items-center justify-center gap-2"><GitCompare size={16} /> Compara├º├úo de Estrutura</div>
 </button>
 <button onClick={() => setActiveTab('config')} className={`flex-1 py-2.5 text-sm font-medium rounded-lg transition-all ${activeTab === 'config' ? 'bg-white text-gray-800 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
 <div className="flex items-center justify-center gap-2"><Database size={16} /> ConfigLocal (Fallback)</div>
 </button>
 <button onClick={() => { setActiveTab('audit'); fetchAuditLogs(); }} className={`flex-1 min-w-[130px] py-2.5 text-sm font-medium rounded-lg transition-all ${activeTab === 'audit' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
 <div className="flex items-center justify-center gap-2"><Monitor size={16} /> Acessos ao Sistema</div>
 </button>
 </div>

 {activeTab === 'tenants' && (
 <div className="space-y-4 animate-fade-in">
 {/* Add Tenant Form */}
 <div className="bg-white p-4 rounded-md shadow-sm border border-gray-200">
 <h3 className="text-base font-semibold mb-3 flex items-center gap-2 text-gray-800"><Plus size={18} className="text-[#32423D]" /> Cadastrar Novo Banco de Cliente</h3>
 <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
 <input placeholder="Nome do Cliente" className="border p-2 rounded" value={newTenant.nome_cliente} onChange={e => setNewTenant({ ...newTenant, nome_cliente: e.target.value })} />
 <input placeholder="Host" className="border p-2 rounded" value={newTenant.db_host} onChange={e => setNewTenant({ ...newTenant, db_host: e.target.value })} />
 <input placeholder="Banco" className="border p-2 rounded" value={newTenant.db_name} onChange={e => setNewTenant({ ...newTenant, db_name: e.target.value })} />
 <input placeholder="Usu├írio" className="border p-2 rounded" value={newTenant.db_user} onChange={e => setNewTenant({ ...newTenant, db_user: e.target.value })} />
 <input placeholder="Senha" type="password" className="border p-2 rounded" value={newTenant.db_pass} onChange={e => setNewTenant({ ...newTenant, db_pass: e.target.value })} />
 <input placeholder="C├│pia Banco Dados (Backup)" className="border p-2 rounded" value={newTenant.copia_banco_dados} onChange={e => setNewTenant({ ...newTenant, copia_banco_dados: e.target.value })} />
 <button onClick={handleAddTenant} disabled={loading} className="bg-[#32423D] text-white p-2 rounded hover:bg-[#32423D]/80 flex items-center justify-center gap-2 md:col-span-3 lg:col-span-1"><Save size={16} /> Cadastrar</button>
 </div>
 </div>
 
 {/* Search + Bulk Actions */}
 <div className="flex items-center gap-3 mb-4">
 <div className="relative flex-1 max-w-sm">
 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={15} />
 <input
 type="search"
 placeholder="Pesquisar banco de dados..."
 value={tenantSearch}
 onChange={(e) => setTenantSearch(e.target.value)}
 className="w-full pl-9 pr-8 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-[#32423D]/20 focus:border-[#32423D] transition-all"
 />
 {tenantSearch && (
