import { useState, useEffect } from 'react';
import { Loader2, ListTodo, CheckCircle, Edit3, Loader, Plus, Save, FileSpreadsheet, ChevronUp, ChevronDown, X } from 'lucide-react';
import * as XLSX from 'xlsx';

const API_BASE = '/api';

const SECTORS = [
 { k: 'Corte', c: 'bg-indigo-500' },
 { k: 'Dobra', c: 'bg-emerald-500' },
 { k: 'Solda', c: 'bg-amber-500' },
 { k: 'Pintura', c: 'bg-sky-500' },
 { k: 'Montagem', c: 'bg-purple-500' }
];

interface Tarefa {
 IdOrdemServicoItemPendencia: string;
 IdProjeto: string;
 Projeto: string;
 DescEmpresa: string;
 IdTag: string;
 Tag: string;
 DescTag: string;
 IdOrdemServico: string;
 IdOrdemServicoItem: string;
 CodMatFabricante: string;
 DescricaoPendencia: string;
 Usuario: string;
 DataCriacao: string;
 TipoTarefa: string;
