 <div className="absolute inset-0 bg-white/50 backdrop-blur-[1px] z-10 flex flex-col gap-2 items-center justify-center">
 <Loader2 className="animate-spin text-[#32423D]" size={32} />
 </div>
 )}

 <div className="table-container relative">
 <table className="w-full text-left text-[11px] whitespace-nowrap">
 <thead className="bg-[#567469] text-white bg-[#567469] text-white bg-[#567469] text-white font-bold uppercase tracking-wider text-[9px] sticky top-0 z-20 shadow-[0_1px_2px_rgba(0,0,0,0.05)]">
 <tr>
 <th className="px-3 py-2 w-16">ID</th>
 <th className="px-3 py-2">Situa├º├úo</th>
 <th className="px-3 py-2">Projeto</th>
 <th className="px-3 py-2">Empresa</th>
 <th className="px-3 py-2">Tag</th>
 <th className="px-3 py-2">C├│d. Mat.</th>
 <th className="px-3 py-2">OS</th>
 <th className="px-3 py-2">Item OS</th>
 <th className="px-3 py-2 min-w-[200px]">Descri├º├úo/Pend├¬ncia</th>
 <th className="px-3 py-2">Resp. Setor</th>
 <th className="px-3 py-2">Usu├írio Resp.</th>
 <th className="px-3 py-2">Criado Em</th>
 </tr>
 </thead>
 <tbody className="divide-y divide-slate-100">
 {items.length === 0 && !loading && (
 <tr>
 <td colSpan={12} className="px-4 py-8 text-center text-slate-400 font-medium">
 Nenhuma tarefa encontrada.
 </td>
 </tr>
 )}
 {items.map(item => (
 <tr key={item.IdOrdemServicoItemPendencia} onClick={() => openEditMode(item)} className={`cursor-pointer group hover:bg-[#E0E800]/10 transition-colors ${item.Status === 'Finalizada' ? 'bg-[#fafcfd] opacity-70' : 'bg-white'}`}>
 <td className="px-3 py-2 font-mono text-slate-600 font-bold flex items-center gap-1.5"><Edit3 size={10} className="text-blue-400 opacity-0 group-hover:opacity-100 transition-opacity" /> #{item.IdOrdemServicoItemPendencia}</td>
 <td className="px-3 py-2">
 {item.Status === 'TarefaAberta' ? (
 <span className="px-1.5 py-0.5 bg-amber-100 text-amber-700 border border-amber-200 rounded text-[9px] font-bold">ABERTA</span>
 ) : (
 <span className="px-1.5 py-0.5 bg-emerald-100 text-emerald-700 border border-emerald-200 rounded text-[9px] font-bold">FINALIZADA</span>
 )}
 </td>
 <td className="px-3 py-2 font-bold text-slate-700 truncate max-w-[150px]">{item.Projeto || 'ÔÇö'}</td>
 <td className="px-3 py-2 truncate max-w-[150px]" title={item.DescEmpresa}>{item.DescEmpresa || 'ÔÇö'}</td>
 <td className="px-3 py-2 font-bold text-[#32423D] truncate max-w-[120px]">{item.Tag || 'ÔÇö'}</td>
 <td className="px-3 py-2 font-mono truncate max-w-[120px]" title={item.CodMatFabricante}>{item.CodMatFabricante || 'ÔÇö'}</td>
 <td className="px-3 py-2 font-mono">{item.IdOrdemServico || 'ÔÇö'}</td>
 <td className="px-3 py-2 font-mono">{item.IdOrdemServicoItem || 'ÔÇö'}</td>
 <td className="px-3 py-2 truncate max-w-[300px] font-medium text-slate-800" title={item.DescricaoPendencia}>{item.DescricaoPendencia}</td>
 <td className="px-3 py-2 text-slate-600 font-medium">{item.SetorResponsavel || 'ÔÇö'}</td>
 <td className="px-3 py-2 text-slate-600">{item.UsuarioResponsavel || 'ÔÇö'}</td>
 <td className="px-3 py-2 text-slate-500 font-mono text-[10px]">{item.DataCriacao}</td>
 </tr>
 ))}
 </tbody>
 </table>
 </div>
 </div>
 </div>
 );
}

import { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import {
 Loader2, Filter, Database, PackageCheck, CheckCircle2,
 Clock, ChevronDown, ChevronUp, Search, X, Building2, Weight, Star,
 ClipboardPen, AlertTriangle, Calendar
} from 'lucide-react';
import { useAppConfig } from '../contexts/AppConfigContext';

// ÔöÇÔöÇÔöÇ Interfaces ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
interface MontagemItem {
 CodMatFabricante: string;
 IdOrdemServico: number;
 IdOrdemServicoItem: number;
 IdProjeto: number;
 Projeto: string;
 IdTag: number;
 Tag: string;
 DescTag: string;
 QtdeTotal: number;
 DescResumo: string;
 DescDetal: string;
 EnderecoArquivo: string;
 IdEmpresa: number;
 Peso: number | null;
 DescEmpresa: string;
 AreaPinturaUnitario: number | null;
 PesoUnitario: number | null;
 sttxtmontagem: string | null;
 RealizadoInicioMontagem: string | null;
 RealizadoFinalMontagem: string | null;
 ProdutoPrincipal: string | null;
 MontagemTotalExecutado: number | null;
 MontagemTotalExecutar: number | null;
 ParcialMontagem: number | null;
 OrdemServicoItemFinalizado?: string | null;
}

type Modo = 'pendentes' | 'concluidos';

interface Filtros {
 IdOrdemServico: string; IdOrdemServicoItem: string; Projeto: string;
 Tag: string; DescResumo: string; DescDetal: string;
 CodMatFabricante: string; IdPlanoDeCorte: string;
 DataInicioMontagemDe: string; DataInicioMontagemAte: string;
 DataFinalMontagemDe: string; DataFinalMontagemAte: string;
}
const filtrosVazios: Filtros = {
 IdOrdemServico: '', IdOrdemServicoItem: '', Projeto: '',
 Tag: '', DescResumo: '', DescDetal: '', CodMatFabricante: '', IdPlanoDeCorte: '',
 DataInicioMontagemDe: '', DataInicioMontagemAte: '',
 DataFinalMontagemDe: '', DataFinalMontagemAte: '',
};

const MODO_CONFIG = {
 pendentes: { label: 'Pendentes', icon: Clock, badge: 'bg-amber-100 text-amber-700 border border-amber-300' },
 concluidos: { label: 'Conclu├¡dos', icon: CheckCircle2, badge: 'bg-emerald-100 text-emerald-700 border border-emerald-300' },
};

// ÔöÇÔöÇÔöÇ Helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function formatarData(val: string | null): string {
 if (!val) return 'ÔÇö';
 const s = String(val).trim();
 const br = s.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
 if (br) return `${br[1]}/${br[2]}/${br[3]}`;
 const iso = s.match(/^(\d{4})-(\d{2})-(\d{2})/);
 if (iso) return `${iso[3]}/${iso[2]}/${iso[1]}`;
 return 'ÔÇö';
}

/** Converte string de data (DD/MM/YYYY ou YYYY-MM-DD) em Date ou null */
function parseDateBR(val: string | null): Date | null {
 if (!val) return null;
 const s = String(val).trim();
 const br = s.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
 if (br) return new Date(+br[3], +br[2] - 1, +br[1]);
 const iso = s.match(/^(\d{4})-(\d{2})-(\d{2})/);
 if (iso) return new Date(+iso[1], +iso[2] - 1, +iso[3]);
 return null;
}

function calcPct(executado: number | null, qtdeTotal: number | null): number | null {
 const ex = Number(executado) || 0;
 const total = Number(qtdeTotal) || 0;
 return total > 0 ? (ex / total) * 100 : null;
}

// ÔöÇÔöÇÔöÇ Modal de Lan├ºamento ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
interface LancarModalProps {
 item: MontagemItem;
 onClose: () => void;
 onSuccess: (idItem: number, novoExecutado: number, novoExecutar: number, concluido: boolean) => void;
}

function LancarModal({ item, onClose, onSuccess }: LancarModalProps) {
 const execar = Number(item.MontagemTotalExecutar) || 0;
 const exec = Number(item.MontagemTotalExecutado) || 0;
 const [qtde, setQtde] = useState<string>(String(execar || item.QtdeTotal));
 const [confirmando, setConfirmando] = useState(false);
 const [salvando, setSalvando] = useState(false);
 const [erro, setErro] = useState('');

 const qtdeNum = parseInt(qtde) || 0;
 const novoExec = exec + qtdeNum;
 // const novoExar = Math.max(0, execar - qtdeNum);
 // Finaliza├º├úo ocorre SOMENTE quando o total executado atingir a quantidade total do item
 const seraFinal = novoExec >= item.QtdeTotal;

 const podeConfirmar = qtdeNum > 0 && qtdeNum <= item.QtdeTotal;

 const handleClick = () => {
 setErro('');
 if (!podeConfirmar) { setErro('Valor inv├ílido. Deve ser > 0 e Ôëñ ' + item.QtdeTotal); return; }
 if (seraFinal) { setConfirmando(true); return; }
 enviar();
 };

 const enviar = async () => {
 setSalvando(true);
 try {
 const res = await fetch('/api/teste-final-montagem/lancar', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({
 IdOrdemServicoItem: item.IdOrdemServicoItem,
 IdOrdemServico: item.IdOrdemServico,
 IdTag: item.IdTag,
 entrada: qtdeNum,
 }),
 });
 const data = await res.json();
 if (data.success) {
 if (data.osFinalizada) alert('Ô£à ' + data.message + '\n\n­ƒÄë Ordem de Servi├ºo encerrada!');
 else if (data.itemFinalizado || data.concluido) alert('Ô£à ' + data.message);
 onSuccess(item.IdOrdemServicoItem, data.novoExecutado, data.novoExecutar, data.concluido);
 onClose();
 } else {
 setErro(data.message || 'Erro desconhecido');
 setConfirmando(false);
 }
 } catch (e: Record<string, unknown>) {
 setErro(e.message);
 } finally {
 setSalvando(false);
 }
 };

 return (
 <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 h-full flex flex-col min-h-0">
 <div className="bg-white rounded-md shadow-2xl w-full max-w-md mx-4 overflow-hidden">

 {/* Header */}
 <div className="bg-indigo-600 px-4 py-2 flex items-center justify-between">
 <div className="flex items-center gap-2 text-white">
 <ClipboardPen size={20} />
 <span className="font-black text-base">Lan├ºar Montagem</span>
 </div>
 <button onClick={onClose} className="text-white/80 hover:text-white"><X size={18} /></button>
 </div>

 <div className="px-6 py-5 space-y-4">
 {/* Info do item */}
 <div className="bg-slate-50 rounded-md px-3 py-1.5 text-xs space-y-1 border border-slate-200">
 <div className="flex gap-6">
 <span><span className="text-slate-400 font-medium">OS:</span> <strong>{item.IdOrdemServico}</strong></span>
 <span><span className="text-slate-400 font-medium">Item:</span> <strong>{item.IdOrdemServicoItem}</strong></span>
 </div>
 <div><span className="text-slate-400">Tag:</span> <strong className="text-indigo-700">{item.Tag}</strong></div>
 <div><span className="text-slate-400">Projeto:</span> {item.Projeto}</div>
 <div className="flex gap-6 pt-1 border-t border-slate-200 mt-2">
 <span><span className="text-slate-400">Executado:</span> <strong className="text-emerald-700">{exec}</strong></span>
 <span><span className="text-slate-400">A Executar:</span> <strong className="text-amber-700">{execar}</strong></span>
 <span><span className="text-slate-400">Total:</span> <strong>{item.QtdeTotal}</strong></span>
 </div>
 </div>

 {/* Input */}
 {!confirmando ? (
 <div>
 <label className="block text-xs font-bold text-slate-600 mb-1.5">
 Quantidade testada:
 </label>
 <input
 type="number"
 min={1}
 max={item.QtdeTotal}
 value={qtde}
 onChange={e => { setQtde(e.target.value); setErro(''); }}
 className="w-full border-2 border-indigo-200 rounded-md px-3 py-1.5 text-xl font-black text-center text-indigo-700 focus:outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200"
 autoFocus
 onKeyDown={e => e.key === 'Enter' && handleClick()}
 />
 {seraFinal && podeConfirmar && (
 <p className="text-[11px] text-amber-600 font-bold mt-1.5 flex items-center gap-1">
 <AlertTriangle size={12} />
 Este lan├ºamento ir├í concluir o setor de Montagem.
 </p>
 )}
 {erro && <p className="text-[11px] text-red-600 font-bold mt-1.5">ÔÜá´©Å {erro}</p>}
 </div>
 ) : (
 /* Tela de confirma├º├úo final */
 <div className="bg-amber-50 border border-amber-300 rounded-md px-3 py-2 text-sm">
 <p className="font-black text-amber-800 text-center mb-2">ÔÜá´©Å Confirmar Finaliza├º├úo</p>
 <p className="text-amber-700 text-center text-xs">
 Esta op├º├úo ir├í <strong>concluir o setor Montagem</strong> para o item {item.IdOrdemServicoItem}.
 {item.ProdutoPrincipal === 'SIM' && ' Por ser Produto Principal, todos os itens da OS ser├úo finalizados.'}
 </p>
 </div>
 )}
 </div>

 {/* Bot├Áes */}
 <div className="px-6 pb-5 flex gap-3">
 <button
 onClick={() => { setConfirmando(false); onClose(); }}
 className="flex-1 px-4 py-2.5 border border-slate-200 rounded-md text-sm font-bold text-slate-600 hover:bg-slate-50 transition-colors"
 >
 Cancelar
 </button>
 {confirmando ? (
 <>
 <button
 onClick={() => setConfirmando(false)}
 className="flex-1 px-4 py-2.5 border border-slate-300 rounded-md text-sm font-bold text-slate-600 hover:bg-slate-50"
 >
 Voltar
 </button>
 <button
 onClick={enviar}
 disabled={salvando}
 className="flex-1 px-4 py-2.5 bg-emerald-600 hover:bg-emerald-700 text-white rounded-md text-sm font-black transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
 >
 {salvando ? <><Loader2 size={14} className="animate-spin" />Salvando...</> : 'Ô£à Confirmar'}
 </button>
 </>
 ) : (
 <button
 onClick={handleClick}
 disabled={salvando}
 className="flex-1 px-4 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-md text-sm font-black transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
 >
 {salvando ? <><Loader2 size={14} className="animate-spin" />Salvando...</> : <><ClipboardPen size={14} />Lan├ºar</>}
 </button>
 )}
 </div>
 </div>
 </div>
 );
}

// ÔöÇÔöÇÔöÇ P├ígina principal ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export default function TesteFinalMontagemPage() {
 const { maxRegistros } = useAppConfig();
 const [itens, setItens] = useState<MontagemItem[]>([]);
 const [loading, setLoading] = useState(false);
 const [error, setError] = useState('');
 const [modo, setModo] = useState<Modo>('pendentes');
 const [filtros, setFiltros] = useState<Filtros>(filtrosVazios);
 const [filtroAberto, setFiltroAberto] = useState(true);
 const [modalItem, setModalItem] = useState<MontagemItem | null>(null);
 const fetchAbortRef = useRef<AbortController | null>(null);

 // Hoje (sem horas) para compara├º├úo de datas
 const hoje = useMemo(() => { const d = new Date(); d.setHours(0,0,0,0); return d; }, []);

 const fetchItens = useCallback(async (modoAtual: Modo = modo) => {
 if (fetchAbortRef.current) fetchAbortRef.current.abort();
 const ctrl = new AbortController();
 fetchAbortRef.current = ctrl;
 setLoading(true); setError('');
 try {
 const params = new URLSearchParams({ modo: modoAtual, limit: String(maxRegistros || 500) });
 // Filtros texto enviados ao servidor (datas filtradas client-side)
 const textKeys: (keyof Filtros)[] = ['IdOrdemServico','IdOrdemServicoItem','Projeto','Tag','DescResumo','DescDetal','CodMatFabricante','IdPlanoDeCorte'];
 textKeys.forEach(k => { const v = filtros[k]; if (v && v.trim()) params.set(k, v.trim()); });
 const res = await fetch(`/api/teste-final-montagem/itens?${params}`, { signal: ctrl.signal });
 if (!res.ok) throw new Error(`Erro HTTP ${res.status}`);
 const result = await res.json();
 if (result.success) setItens(result.data || []);
 else setError(result.message || 'Erro ao buscar dados');
 } catch (err: Record<string, unknown>) {
 if (err.name !== 'AbortError') setError(err.message);
 } finally { setLoading(false); }
 }, [filtros, maxRegistros, modo]);

 useEffect(() => { fetchItens(modo); }, [modo]);

 const handleSearch = () => fetchItens(modo);
 const handleLimpar = () => { setFiltros(filtrosVazios); setTimeout(() => fetchItens(modo), 50); };
 const handleKeyDown = (e: React.KeyboardEvent) => { if (e.key === 'Enter') handleSearch(); };

 // Ap├│s lan├ºamento: re-busca completa para garantir estado correto
 const handleLancamentoSucesso = () => {
 fetchItens(modo);
 };

 // Filtragem client-side por intervalo de datas
 const itensFiltrados = useMemo(() => {
 let result = itens;
 const { DataInicioMontagemDe, DataInicioMontagemAte, DataFinalMontagemDe, DataFinalMontagemAte } = filtros;
 if (DataInicioMontagemDe) { const de = new Date(DataInicioMontagemDe + 'T00:00:00'); result = result.filter(it => { const d = parseDateBR(it.RealizadoInicioMontagem); return d !== null && d >= de; }); }
 if (DataInicioMontagemAte) { const ate = new Date(DataInicioMontagemAte + 'T00:00:00'); result = result.filter(it => { const d = parseDateBR(it.RealizadoInicioMontagem); return d !== null && d <= ate; }); }
 if (DataFinalMontagemDe) { const de = new Date(DataFinalMontagemDe + 'T00:00:00'); result = result.filter(it => { const d = parseDateBR(it.RealizadoFinalMontagem); return d !== null && d >= de; }); }
 if (DataFinalMontagemAte) { const ate = new Date(DataFinalMontagemAte + 'T00:00:00'); result = result.filter(it => { const d = parseDateBR(it.RealizadoFinalMontagem); return d !== null && d <= ate; }); }
 return result;
 }, [itens, filtros]);
 const mc = MODO_CONFIG[modo];
 // const ModoIcon = mc.icon;

 return (
 <div className="flex flex-col h-[calc(100vh-8rem)] bg-[#f1f5f9] text-slate-800">

 {/* Modal */}
 {modalItem && (
 <LancarModal
 item={modalItem}
 onClose={() => setModalItem(null)}
 onSuccess={handleLancamentoSucesso}
 />
 )}

 {/* ÔöÇÔöÇ Header ÔöÇÔöÇ */}
 <div className="shrink-0 bg-white border-b border-slate-200 shadow-sm px-5 py-3">
 <div className="flex items-center justify-between gap-4">
 <div className="flex items-center gap-3">
 <div className="h-10 w-10 bg-indigo-100 text-indigo-600 rounded-md flex items-center justify-center shadow-sm shrink-0">
 <PackageCheck size={22} />
 </div>
 <div>
 
 <p className="text-[11px] text-slate-500 mt-0.5">Itens aptos para montagem e envio</p>
 </div>
 </div>
 <div className="flex items-center gap-3">
 <div className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold ${mc.badge}`}>
 <Database size={13} />
 {loading ? '...' : `${itensFiltrados.length} itens`}
 </div>
 <div className="flex rounded-lg overflow-hidden border border-slate-200 shadow-sm">
 {(['pendentes', 'concluidos'] as Modo[]).map(m => {
 const cfg = MODO_CONFIG[m]; const Icon = cfg.icon; const ativo = modo === m;
 return (
 <button key={m} onClick={() => setModo(m)}
 className={`flex items-center gap-1.5 px-3 py-2 text-xs font-bold transition-all ${ativo ? m === 'pendentes' ? 'bg-amber-500 text-white' : 'bg-emerald-500 text-white' : 'bg-white text-slate-500 hover:bg-slate-50'}`}>
 <Icon size={13} />{cfg.label}
 </button>
 );
 })}
 </div>
 </div>
 </div>
 </div>

 {/* ÔöÇÔöÇ Filtros ÔöÇÔöÇ */}
 <div className="shrink-0 bg-white border-b border-slate-200 mx-4 mt-3 rounded-md shadow-sm overflow-hidden">
 <button className="w-full flex items-center justify-between px-4 py-2.5 text-xs font-bold text-slate-600 hover:bg-slate-50 transition-colors"
 onClick={() => setFiltroAberto(v => !v)}>
 <span className="flex items-center gap-2"><Filter size={13} />Filtros de Pesquisa</span>
 {filtroAberto ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
