 <div className="flex flex-wrap gap-2 mt-2.5">
 {([
 { key: 'IdOrdemServico', label: 'OS', w: 'w-24' },
 { key: 'IdOrdemServicoItem', label: 'Item', w: 'w-20' },
 { key: 'Projeto', label: 'Projeto', w: 'w-36' },
 { key: 'Tag', label: 'Tag', w: 'w-32' },
 { key: 'DescResumo', label: 'Desc. Resumo', w: 'w-40' },
 { key: 'DescDetal', label: 'Desc. Detal', w: 'w-40' },
 { key: 'CodMatFabricante', label: 'C├│d. Fabri.', w: 'w-32' },
 { key: 'IdPlanoDeCorte', label: 'Plano Corte', w: 'w-28' },
 ] as { key: keyof Filtros; label: string; w: string }[]).map(({ key, label, w }) => (
 <div key={key} className={`flex items-center bg-slate-50 border border-slate-200 rounded-lg px-2.5 shadow-sm focus-within:border-indigo-400 focus-within:ring-1 focus-within:ring-indigo-200 ${w}`}>
 <input type="text" placeholder={label} value={filtros[key]}
 onChange={e => setFiltros(p => ({ ...p, [key]: e.target.value }))}
 onKeyDown={handleKeyDown}
 className="w-full text-xs py-1.5 outline-none bg-transparent font-medium text-slate-700 placeholder:text-slate-400" />
 </div>
 ))}
 <button onClick={handleSearch} className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-100 border border-emerald-200 text-emerald-800 hover:bg-emerald-200 text-xs font-bold rounded-lg transition-colors shadow-sm">
 <Search size={13} />Pesquisar
 </button>
 <button onClick={handleLimpar} className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-200 hover:bg-slate-300 text-slate-600 text-xs font-bold rounded-lg transition-colors">
 <X size={13} />Limpar
 </button>
 </div>
 {/* Linha 2 ÔÇô intervalo de datas (filtro client-side) */}
 <div className="flex flex-wrap items-center gap-2 mt-2 pt-2 border-t border-slate-100">
 <span className="flex items-center gap-1 text-[10px] font-bold text-slate-400 uppercase tracking-wide">
 <Calendar size={11} />Datas
 </span>
 <span className="text-[10px] text-slate-500 font-semibold">In├¡cio Mont.:</span>
 <input type="date" value={filtros.DataInicioMontagemDe}
 onChange={e => setFiltros(p => ({ ...p, DataInicioMontagemDe: e.target.value }))}
 className="text-xs py-1 px-2 bg-slate-50 border border-slate-200 rounded-lg outline-none text-slate-700 focus:border-indigo-400 w-34" />
 <span className="text-[10px] text-slate-400">at├®</span>
 <input type="date" value={filtros.DataInicioMontagemAte}
 onChange={e => setFiltros(p => ({ ...p, DataInicioMontagemAte: e.target.value }))}
 className="text-xs py-1 px-2 bg-slate-50 border border-slate-200 rounded-lg outline-none text-slate-700 focus:border-indigo-400 w-34" />
 <span className="text-[10px] text-slate-500 font-semibold ml-2">Final Mont.:</span>
 <input type="date" value={filtros.DataFinalMontagemDe}
 onChange={e => setFiltros(p => ({ ...p, DataFinalMontagemDe: e.target.value }))}
 className="text-xs py-1 px-2 bg-slate-50 border border-slate-200 rounded-lg outline-none text-slate-700 focus:border-indigo-400 w-34" />
 <span className="text-[10px] text-slate-400">at├®</span>
 <input type="date" value={filtros.DataFinalMontagemAte}
 onChange={e => setFiltros(p => ({ ...p, DataFinalMontagemAte: e.target.value }))}
 className="text-xs py-1 px-2 bg-slate-50 border border-slate-200 rounded-lg outline-none text-slate-700 focus:border-indigo-400 w-34" />
 </div>
 </div>
 )}
 </div>

 {/* ÔöÇÔöÇ Tabela ÔöÇÔöÇ */}
 <div className="flex-1 overflow-hidden mx-4 my-3 relative">
 {loading && (
 <div className="absolute inset-0 bg-white/70 backdrop-blur-[1px] z-20 flex items-center justify-center rounded-md">
 <div className="flex items-center gap-2 text-indigo-600 font-bold text-sm bg-white shadow-lg px-5 py-3 rounded-md border border-indigo-100">
 <Loader2 className="animate-spin" size={20} />Carregando itens...
 </div>
 </div>
 )}
 {error && (
 <div className="bg-red-50 text-red-700 px-3 py-1.5 rounded-md text-sm font-bold border border-red-200 mb-3">ÔÜá´©Å {error}</div>
 )}

 <div className="h-full bg-white rounded-md shadow-sm border border-slate-200 overflow-hidden flex flex-col">
 {!loading && !error && itensFiltrados.length === 0 && (
 <div className="bg-amber-50 border-b border-amber-200 px-3 py-1.5 flex items-center gap-3 text-amber-800 animate-in fade-in slide-in-from-top-2 duration-300">
 <AlertTriangle size={18} className="text-amber-500" />
 <div>
 <p className="text-sm font-black">Nenhum registro encontrado</p>
 <p className="text-[11px] opacity-80">A pesquisa foi conclu├¡da, mas n├úo h├í itens {modo === 'concluidos' ? 'conclu├¡dos' : 'pendentes'} para os filtros aplicados.</p>
 </div>
 </div>
 )}
 <div className="overflow-x-auto overflow-y-auto flex-1 custom-scrollbar">
 <table className="w-full text-xs text-left">
 <thead className="bg-[#567469] text-white bg-[#567469] text-white text-[10px] text-white uppercase bg-[#567469] sticky top-0 z-10 border-b border-white/20 shadow-sm">
 <tr>
 <th className="px-3 py-2 font-black whitespace-nowrap">OS / Item</th>
 <th className="px-3 py-2 font-black whitespace-nowrap">Projeto</th>
 <th className="px-3 py-2 font-black whitespace-nowrap">Tag</th>
 <th className="px-3 py-2 font-black whitespace-nowrap">Empresa</th>
 <th className="px-3 py-2 font-black text-center whitespace-nowrap">Qtde</th>
 <th className="px-3 py-2 font-black text-right whitespace-nowrap">Executado</th>
 <th className="px-3 py-2 font-black text-right whitespace-nowrap">A Executar</th>
 <th className="px-3 py-2 font-black text-center whitespace-nowrap">Parcial</th>
 <th className="px-3 py-2 font-black text-center whitespace-nowrap">A├º├úo</th>
 <th className="px-3 py-2 font-black text-right whitespace-nowrap">Peso Un.</th>
 <th className="px-3 py-2 font-black whitespace-nowrap">C├│d. Fabri.</th>
 <th className="px-3 py-2 font-black whitespace-nowrap">Desc. Resumo</th>
 <th className="px-3 py-2 font-black text-center whitespace-nowrap">Principal</th>
 <th className="px-3 py-2 font-black whitespace-nowrap">In├¡cio Mont.</th>
 <th className="px-3 py-2 font-black whitespace-nowrap">Final Mont.</th>
 </tr>
 </thead>
 <tbody>
 {itensFiltrados.length > 0 ? (
 itensFiltrados.map((item, idx) => {
 const isPrincipal = item.ProdutoPrincipal === 'S' || item.ProdutoPrincipal === 'SIM';
 const pct = calcPct(item.MontagemTotalExecutado, item.QtdeTotal);
 const concluido = item.sttxtmontagem === 'C' || item.OrdemServicoItemFinalizado === 'C';
 // Cores de data: vermelho se > hoje, verde se Ôëñ hoje
 const dInicio = parseDateBR(item.RealizadoInicioMontagem);
 const corInicio = dInicio ? (dInicio > hoje ? 'text-red-600 font-bold' : 'text-emerald-600 font-bold') : 'text-slate-400';
 const dFinal = parseDateBR(item.RealizadoFinalMontagem);
 const corFinal = dFinal ? (dFinal > hoje ? 'text-red-600 font-bold' : 'text-emerald-600 font-bold') : 'text-slate-400';

 return (
 <tr key={`${item.IdOrdemServicoItem}-${idx}`}
 className={`border-b border-slate-100 hover:bg-indigo-50/40 transition-colors ${isPrincipal ? 'bg-amber-50/30' : ''} ${concluido ? 'opacity-60' : ''}`}>
 <td className="px-3 py-1.5 font-bold text-slate-700 whitespace-nowrap">
 {item.IdOrdemServico}<span className="text-slate-400 font-normal"> / {item.IdOrdemServicoItem}</span>
 </td>
 <td className="px-3 py-1.5 text-slate-600 max-w-[120px] truncate" title={item.Projeto}>{item.Projeto}</td>
 <td className="px-3 py-1.5 font-bold text-indigo-700 whitespace-nowrap max-w-[100px] truncate" title={item.Tag}>{item.Tag}</td>
 <td className="px-3 py-1.5 whitespace-nowrap">
 <span className="flex items-center gap-1 text-slate-500">
 <Building2 size={11} className="shrink-0" />
 <span className="truncate max-w-[100px]" title={item.DescEmpresa}>{item.DescEmpresa}</span>
 </span>
 </td>
 <td className="px-3 py-1.5 text-center font-bold text-indigo-600 bg-indigo-50/60">{item.QtdeTotal}</td>
 <td className="px-3 py-1.5 text-right font-semibold text-emerald-700">{item.MontagemTotalExecutado ?? 'ÔÇö'}</td>
 <td className="px-3 py-1.5 text-right font-semibold text-amber-700">{item.MontagemTotalExecutar ?? 'ÔÇö'}</td>
 <td className="px-3 py-1.5 text-center">
 <span className="inline-flex items-center gap-1.5 font-bold text-[11px]">
 {/* executado / total */}
 <span className="text-emerald-700">{Number(item.MontagemTotalExecutado ?? 0)}</span>
 <span className="text-slate-400 font-normal">/</span>
 <span className="text-slate-600">{item.QtdeTotal}</span>
 {/* badge percentual */}
 {pct !== null && (
 <span className={`inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-bold ${
 pct >= 100 ? 'bg-emerald-100 text-emerald-700'
 : pct >= 50 ? 'bg-amber-100 text-amber-700'
 : 'bg-red-100 text-red-700'
 }`}>
 {pct.toFixed(0)}%
 </span>
 )}
 </span>
 </td>
 <td className="px-3 py-1.5 text-center">
 {concluido ? (
 <span className="inline-flex items-center gap-0.5 bg-emerald-100 text-emerald-700 rounded px-1.5 py-0.5 text-[9px] font-bold">
 <CheckCircle2 size={9} />OK
 </span>
 ) : (
 <button
 onClick={() => setModalItem(item)}
 className="inline-flex items-center gap-1 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg px-2 py-1 text-[10px] font-bold transition-colors shadow-sm"
 >
 <ClipboardPen size={10} />Lan├ºar
 </button>
 )}
 </td>
 <td className="px-3 py-1.5 text-right text-slate-500">
 {item.PesoUnitario !== null ? (
 <span className="flex items-center justify-end gap-0.5"><Weight size={10} />{Number(item.PesoUnitario).toFixed(2)}</span>
 ) : 'ÔÇö'}
 </td>
 <td className="px-3 py-1.5 font-mono text-[10px] text-slate-500 whitespace-nowrap">{item.CodMatFabricante}</td>
 <td className="px-3 py-1.5 max-w-[180px] truncate text-slate-600" title={item.DescResumo}>{item.DescResumo}</td>
 <td className="px-3 py-1.5 text-center">
 {isPrincipal && (
 <span className="inline-flex items-center gap-0.5 bg-amber-100 text-amber-700 border border-amber-300 rounded px-1.5 py-0.5 text-[9px] font-bold">
 <Star size={9} fill="currentColor" />PP
 </span>
 )}
 </td>
 <td className={`px-3 py-1.5 whitespace-nowrap text-[10px] ${corInicio}`}>{formatarData(item.RealizadoInicioMontagem)}</td>
 <td className={`px-3 py-1.5 whitespace-nowrap text-[10px] ${corFinal}`}>{formatarData(item.RealizadoFinalMontagem)}</td>
 </tr>
 );
 })
 ) : (
 <tr>
 <td colSpan={15} className="px-6 py-16 text-center">
 <div className="flex flex-col items-center gap-2 text-slate-400">
 <PackageCheck size={36} className="opacity-30" />
 <span className="font-medium text-sm">{loading ? 'Carregando...' : `Nenhum item ${modo === 'concluidos' ? 'conclu├¡do' : 'pendente'} encontrado`}</span>
 </div>
 </td>
 </tr>
 )}
 </tbody>
 </table>
 </div>
 </div>
 </div>
 </div>
 );
}

import React, { useState, useEffect } from 'react';
import { Users, Search, Plus, Edit2, Trash2, Key, Shield, User, X, Check, Loader2 } from 'lucide-react';
import { useToast } from '../contexts/ToastContext';

const API_BASE = '/api';

interface Usuario {
 idUsuario?: number;
 NomeCompleto: string;
 Login: string;
 Senha?: string;
 TipoUsuario: string;
 email?: string;
 status: string;
}

export default function UsuarioPage() {
 const { addToast } = useToast();
 const [usuarios, setUsuarios] = useState<Usuario[]>([]);
 const [loading, setLoading] = useState(true);
 const [searchTerm, setSearchTerm] = useState('');

 // Modal state
 const [showModal, setShowModal] = useState(false);
 const [editingUsuario, setEditingUsuario] = useState<Usuario | null>(null);
 const [formData, setFormData] = useState<Usuario>({
 NomeCompleto: '',
 Login: '',
 Senha: '',
 TipoUsuario: 'C',
 status: 'A'
 });
 const [submitting, setSubmitting] = useState(false);

 useEffect(() => {
 fetchUsuarios();
 }, []);

 const fetchUsuarios = async () => {
 setLoading(true);
 try {
 const res = await fetch(`${API_BASE}/usuario`);
 const data = await res.json();
 if (data.success) {
 setUsuarios(data.data);
 }
 } catch {
 console.error('Error fetching users:', error);
 addToast({ type: 'error', title: 'Erro', message: 'Erro ao carregar usu├írios' });
 } finally {
 setLoading(false);
 }
 };

 const handleSearch = (term: string) => {
 setSearchTerm(term);
 };

 const filteredUsuarios = usuarios.filter(u =>
 u.NomeCompleto.toLowerCase().includes(searchTerm.toLowerCase()) ||
 u.Login.toLowerCase().includes(searchTerm.toLowerCase())
 );

 const handleOpenModal = (usuario: Usuario | null = null) => {
 if (usuario) {
 setEditingUsuario(usuario);
 setFormData({
 ...usuario,
 Senha: '' // Don't show password on edit
 });
 } else {
 setEditingUsuario(null);
 setFormData({
 NomeCompleto: '',
 Login: '',
 Senha: '',
 TipoUsuario: 'C',
 status: 'A'
 });
 }
 setShowModal(true);
 };

 const handleSubmit = async (e: React.FormEvent) => {
 e.preventDefault();

 if (!formData.NomeCompleto || !formData.Login || (!editingUsuario && !formData.Senha)) {
 addToast({ type: 'error', title: 'Aten├º├úo', message: 'Preencha todos os campos obrigat├│rios' });
 return;
 }

 setSubmitting(true);
 try {
 const url = editingUsuario
 ? `${API_BASE}/usuario/${editingUsuario.idUsuario}`
 : `${API_BASE}/usuario`;

 const method = editingUsuario ? 'PUT' : 'POST';

 const res = await fetch(url, {
 method,
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify(formData)
 });

 const data = await res.json();
 if (data.success) {
 addToast({
 type: 'success',
 title: 'Sucesso',
 message: editingUsuario ? 'Usu├írio atualizado!' : 'Usu├írio criado!'
 });
 setShowModal(false);
 fetchUsuarios();
 } else {
 addToast({ type: 'error', title: 'Erro', message: data.message || 'Erro ao salvar' });
 }
 } catch {
 console.error('Error saving user:', error);
 addToast({ type: 'error', title: 'Erro', message: 'Erro de conex├úo' });
 } finally {
 setSubmitting(false);
 }
 };

 const handleDelete = async (id: number) => {
 if (!window.confirm('Tem certeza que deseja excluir este usu├írio?')) return;

 try {
 const res = await fetch(`${API_BASE}/usuario/${id}`, { method: 'DELETE' });
 const data = await res.json();

 if (data.success) {
 addToast({ type: 'success', title: 'Sucesso', message: 'Usu├írio exclu├¡do' });
 fetchUsuarios();
 } else {
 addToast({ type: 'error', title: 'Erro', message: 'Erro ao excluir' });
 }
 } catch {
 console.error('Error deleting user:', error);
 addToast({ type: 'error', title: 'Erro', message: 'Erro de conex├úo' });
 }
 };

 return (
 <div className="p-6 max-w-[1600px] mx-auto animate-fade-in pb-20 h-full flex flex-col min-h-0">
 {/* Header */}
 <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
 <div className="flex items-center gap-3">
 <div className="p-2 bg-[#32423D] rounded-lg shadow-lg shadow-[#32423D]/20">
 <Users size={24} className="text-[#E0E800]" />
 </div>
 <div>
 
 <p className="text-gray-500 text-sm">Gerenciamento de acesso ao sistema</p>
 </div>
 </div>

 <div className="flex items-center gap-3 w-full md:w-auto">
 <div className="relative flex-1 md:w-80 flex items-center gap-2 group">
 <div className="relative flex-1">
 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#32423D] transition-colors" size={20} />
 <input
 type="text"
 placeholder="Buscar por nome ou login..."
 className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-200 rounded-md focus:ring-2 focus:ring-[#32423D] focus:border-transparent outline-none transition-all shadow-sm group-hover:shadow-md"
 value={searchTerm}
 onChange={(e) => handleSearch(e.target.value)}
 />
 </div>
 {searchTerm && (
 <button onClick={() => handleSearch('')} className="p-2.5 rounded-md border border-gray-200 text-gray-500 hover:text-red-500 hover:bg-red-50 hover:border-red-200 bg-white shadow-sm transition-colors" title="Limpar pesquisa">
 <X size={20} />
 </button>
 )}
 </div>
 <button
 onClick={() => handleOpenModal()}
 className="flex items-center gap-2 bg-[#32423D] text-[#E0E800] px-4 py-2.5 rounded-md font-bold hover:bg-[#2a3833] transition-colors shadow-lg shadow-[#32423D]/20"
 >
 <Plus size={20} />
 <span className="hidden sm:inline">Novo Usu├írio</span>
 </button>
 </div>
 </div>

 {/* List */}
 <div className="bg-white rounded-md shadow-sm border border-gray-100 overflow-hidden">
 <div className="overflow-auto flex-1">
 <table className="w-full">
 <thead className="bg-[#567469] text-white bg-[#567469] text-white text-white bg-[#567469] border-b border-white/20">
 <tr>
 <th className="text-left py-4 px-6 text-xs font-semibold text-white uppercase tracking-wider">Nome</th>
 <th className="text-left py-4 px-6 text-xs font-semibold text-white uppercase tracking-wider">Login</th>
 <th className="text-left py-4 px-6 text-xs font-semibold text-white uppercase tracking-wider">Tipo</th>
 <th className="text-left py-4 px-6 text-xs font-semibold text-white uppercase tracking-wider">Status</th>
 <th className="text-right py-4 px-6 text-xs font-semibold text-white uppercase tracking-wider">A├º├Áes</th>
 </tr>
 </thead>
 <tbody className="divide-y divide-gray-50">
 {loading ? (
 <tr>
 <td colSpan={5} className="py-8 text-center text-gray-500">
 <div className="flex flex-col items-center gap-2">
 <Loader2 className="animate-spin text-[#32423D]" size={24} />
 <p className="text-sm">Carregando usu├írios...</p>
 </div>
 </td>
 </tr>
 ) : filteredUsuarios.length === 0 ? (
 <tr>
 <td colSpan={5} className="py-12 text-center text-gray-400">
 Nenhum usu├írio encontrado
 </td>
 </tr>
 ) : (
 filteredUsuarios.map((usuario) => (
 <tr key={usuario.idUsuario} className="hover:bg-gray-50/50 transition-colors group">
 <td className="py-4 px-6">
 <div className="flex items-center gap-3">
 <div className="w-10 h-10 rounded-full bg-[#E0E800]/20 flex items-center justify-center text-[#32423D] font-bold text-lg">
 {usuario.NomeCompleto.charAt(0).toUpperCase()}
 </div>
 <span className="font-medium text-gray-800">{usuario.NomeCompleto}</span>
 </div>
 </td>
 <td className="py-4 px-6 text-gray-600 font-mono text-sm">{usuario.Login}</td>
 <td className="py-4 px-6">
 <span className={`inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium ${usuario.TipoUsuario === 'A' || usuario.TipoUsuario === 'Admin'
 ? 'bg-purple-100 text-purple-700'
 : 'bg-[#E0E800]/40 text-[#32423D]'
 }`}>
 {usuario.TipoUsuario === 'A' || usuario.TipoUsuario === 'Admin' ? (
 <Shield size={12} />
 ) : (
 <User size={12} />
 )}
 {usuario.TipoUsuario === 'A' || usuario.TipoUsuario === 'Admin' ? 'Admin' : 'Comum'}
 </span>
 </td>
 <td className="py-4 px-6">
 <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-700">
 <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
 Ativo
 </span>
 </td>
 <td className="py-4 px-6 text-right">
 <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
 <button
 onClick={() => handleOpenModal(usuario)}
 className="p-2 text-[#32423D] hover:bg-[#E0E800]/10 rounded-lg transition-colors"
 title="Editar"
 >
 <Edit2 size={18} />
 </button>
 <button
 onClick={() => usuario.idUsuario && handleDelete(usuario.idUsuario)}
 className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
 title="Excluir"
 >
 <Trash2 size={18} />
 </button>
 </div>
 </td>
 </tr>
 ))
 )}
 </tbody>
 </table>
 </div>
 </div>

 {/* Modal */}
 {showModal && (
 <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 p-4 animate-fade-in">
 <div className="bg-white rounded-md shadow-2xl w-full max-w-lg overflow-hidden animate-scale-in" onClick={(e) => e.stopPropagation()}>
 <div className="px-4 py-2 border-b border-gray-100 flex items-center justify-between bg-gray-50">
 <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
 {editingUsuario ? <Edit2 size={20} className="text-[#32423D]" /> : <Plus size={20} className="text-[#32423D]" />}
 {editingUsuario ? 'Editar Usu├írio' : 'Novo Usu├írio'}
 </h2>
 <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-gray-600 transition-colors">
 <X size={24} />
 </button>
 </div>

 <form onSubmit={handleSubmit} className="p-6 space-y-4">
 <div>
 <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
 <div className="relative">
 <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
 <input
 type="text"
 required
