 </div>
 </form>
 </div>
 </div>
 )}
 </div>
 );
}

import { useState, useEffect, useMemo } from 'react';
import { X, Loader2, RefreshCw, Eye, ChevronDown, ChevronUp, XCircle } from 'lucide-react';
import { useAppConfig } from '../contexts/AppConfigContext';

const API_BASE = '/api';

interface PendenciaGlobal {
 IdOrdemServicoItemPendencia: string;
 IdOrdemServico: string;
 IdOrdemServicoItem: string;
 IdPLanodeCorte: string;
 IdRomaneio: string;
 IdProjeto: string;
 IdTag: string;
 CodMatFabricante: string;
 Projeto: string;
 Tag: string;
 DescEmpresa: string;
 IdMaterial: string;
 DescResumo: string;
 DescDetal: string;
 Espessura: string;
 MaterialSW: string;
 EnderecoArquivo: string;
 DescricaoPendencia: string;
 Usuario: string;
 CriadoPorSetor: string;
 DataCriacao: string;
 Estatus: string;
 txtCorte: string;
 txtdobra: string;
 txtSolda: string;
