 <th className="px-3 py-1.5">Setor Resp.</th>
 <th className="px-3 py-1.5">Tp Cadastro</th>
 <th className="px-3 py-1.5">Data Exec.</th>
 <th className="px-3 py-1.5">Controle Email</th>
 <th className="px-3 py-1.5">Email Resp.</th>
 <th className="px-3 py-1.5">Usu├írio Resp. (Final)</th>
 <th className="px-3 py-1.5">Tipo Tarefa / Registro</th>
 <th className="px-3 py-1.5">Desc. Finaliza├º├úo</th>
 <th className="px-3 py-1.5">Setor Fin.</th>
 <th className="px-3 py-1.5">A├º├Áes</th>
 </tr>
 </thead>
 <tbody className="divide-y divide-slate-100">
 {filteredItems.length === 0 && !loading && (
